5b3432a8-0bcf-4838-9cf8-2baa72f5a908	2026-03-17 12:31:36.107932+00	2026-03-17 12:35:04.380826+00	system	system	{"maintainer": "dl.mlsedevops@amd.com", "com.amd.aim.title": "Command A Reasoning 08 2025", "com.amd.aim.model.tags": "text-generation, conversational, chat, multilingual", "com.amd.aim.model.source": "https://huggingface.co/CohereLabs/command-a-reasoning-08-2025", "com.amd.aim.release.notes": "", "com.amd.aim.model.variants": "CohereLabs/command-a-reasoning-08-2025", "com.amd.aim.model.publisher": "Cohere Labs", "com.amd.aim.description.full": "Command A Reasoning is a 111 billion parameter open-weights language model from Cohere Labs, optimized for tool use, agentic tasks, and multilingual use cases with configurable reasoning capabilities. It uses an optimized transformer architecture with sliding window attention (window size 4096) and RoPE for local context modeling, plus global attention layers without positional embeddings for unrestricted token interactions. The model can operate with reasoning on for increased performance or reasoning off for lower latency. It supports tool use with citation grounding, handles 23 languages, and provides a 256k context length with 32k output length. Fine-tuned using supervised fine-tuning (SFT) and preference training.", "com.amd.aim.hfToken.required": "True", "org.opencontainers.image.title": "CohereLabs/command-a-reasoning-08-2025", "com.amd.aim.model.canonicalName": "CohereLabs/command-a-reasoning-08-2025", "org.opencontainers.image.source": "https://github.com/silogen/aim-build", "org.opencontainers.image.vendor": "AMD", "org.opencontainers.image.authors": "", "org.opencontainers.image.created": "2026-02-26T09:30:28Z", "org.opencontainers.image.version": "", "org.opencontainers.image.licenses": "CC-BY-NC-4.0, MIT", "org.opencontainers.image.ref.name": "ubuntu", "org.opencontainers.image.revision": "ba04507c298243be84f307bff801a2213e7f6143", "org.opencontainers.image.description": "111B parameter language model w