5cf3ca4d-ee86-46a4-aeea-2a475ee86edf	2026-03-17 12:31:36.107946+00	2026-03-17 12:35:04.380859+00	system	system	{"maintainer": "dl.mlsedevops@amd.com", "com.amd.aim.title": "DeepSeek R1 0528", "com.amd.aim.model.tags": "text-generation, chat", "com.amd.aim.model.source": "https://huggingface.co/deepseek-ai/DeepSeek-R1-0528", "com.amd.aim.release.notes": "", "com.amd.aim.model.variants": "deepseek-ai/DeepSeek-R1-0528", "com.amd.aim.model.publisher": "DeepSeek", "com.amd.aim.description.full": "DeepSeek-R1-0528 is an updated version of DeepSeek-R1 from DeepSeek AI, a 671 billion total parameter mixture-of-experts (MoE) reasoning model with 37 billion active parameters. This version introduces increased computational resources and algorithmic optimization during post-training for deeper reasoning. It features reduced hallucination rate, function calling support, system prompt support, and a maximum generation length of 64K tokens with a 128K token context length. The model uses the DeepSeek-V3 architecture and is trained via reinforcement learning to develop chain-of-thought reasoning capabilities. Licensed under MIT with support for commercial use and distillation.", "com.amd.aim.hfToken.required": "False", "org.opencontainers.image.title": "deepseek-ai/DeepSeek-R1-0528", "com.amd.aim.model.canonicalName": "deepseek-ai/DeepSeek-R1-0528", "org.opencontainers.image.source": "https://github.com/silogen/aim-build", "org.opencontainers.image.vendor": "AMD", "org.opencontainers.image.authors": "", "org.opencontainers.image.created": "2026-03-04T09:15:29Z", "org.opencontainers.image.version": "", "org.opencontainers.image.licenses": "MIT", "org.opencontainers.image.ref.name": "ubuntu", "org.opencontainers.image.revision": "268e89c5c4c0dcb4edfd448a8e13606699cac497", "org.opencontainers.image.description": "671B parameter MoE reasoning model with 37B active parameters, updated version of DeepSeek-R1.", "org.opencontainers.image.documentation": "", "com.amd.aim.model.recommended