ular MoE multimodal model with 41B active parameters and vision capabilities.", "org.opencontainers.image.documentation": "", "com.amd.aim.model.recommendedDeployments": "[{'gpuModel': 'MI300X', 'gpuCount': 8, 'precision': 'fp8', 'metric': 'latency', 'description': 'Optimized for latency on MI300X using fp8 precision'}, {'gpuModel': 'MI300X', 'gpuCount': 8, 'precision': 'fp8', 'metric': 'throughput', 'description': 'Optimized for throughput on MI300X using fp8 precision'}, {'gpuModel': 'MI325X', 'gpuCount': 8, 'metric': 'latency', 'description': 'Optimized for latency on MI325X using fp8 precision', 'profileId': 'vllm-mi325x-fp8-tp8-latency'}, {'gpuModel': 'MI325X', 'gpuCount': 8, 'metric': 'throughput', 'description': 'Optimized for throughput on MI325X using fp8 precision', 'profileId': 'vllm-mi325x-fp8-tp8-throughput'}, {'gpuModel': 'MI350X', 'gpuCount': 8, 'precision': 'fp8', 'metric': 'latency', 'description': 'Optimized for latency on MI350X using fp8 precision'}, {'gpuModel': 'MI350X', 'gpuCount': 8, 'precision': 'fp8', 'metric': 'throughput', 'description': 'Optimized for throughput on MI350X using fp8 precision'}, {'gpuModel': 'MI355X', 'gpuCount': 8, 'precision': 'fp8', 'metric': 'latency', 'description': 'Optimized for latency on MI355X using fp8 precision'}, {'gpuModel': 'MI355X', 'gpuCount': 8, 'precision': 'fp8', 'metric': 'throughput', 'description': 'Optimized for throughput on MI355X using fp8 precision'}]"}	amdenterpriseai-aim-mistralai-mistral-large-3-675-0.10.0-a878ab	amdenterpriseai/aim-mistralai-mistral-large-3-675b-instruct-2512:0.10.0	Ready
