a5dbf7de-27ae-4019-a95a-a35b887ab16d	2026-03-17 12:31:36.108044+00	2026-03-17 12:35:04.381032+00	system	system	{"maintainer": "dl.mlsedevops@amd.com", "com.amd.aim.title": "Qwen3 32B", "com.amd.aim.model.tags": "text-generation, chat", "com.amd.aim.model.source": "https://huggingface.co/Qwen/Qwen3-32B", "com.amd.aim.release.notes": "", "com.amd.aim.model.variants": "Qwen/Qwen3-32B, Qwen/Qwen3-32B-FP8", "com.amd.aim.model.publisher": "Qwen", "com.amd.aim.description.full": "Qwen3-32B is a 32.8 billion parameter dense causal language model from the Qwen series by the Qwen Team at Alibaba Group. It features 64 layers with Grouped-Query Attention (GQA, 64 Q heads and 8 KV heads). The model supports seamless switching between thinking mode (for complex logical reasoning, math, and coding) and non-thinking mode (for efficient general-purpose dialogue). It provides tool calling and agentic capabilities, supports over 100 languages and dialects, and has a native context length of 32,768 tokens, extendable to 131,072 tokens with YaRN. Trained through pretraining and post-training stages.", "com.amd.aim.hfToken.required": "False", "org.opencontainers.image.title": "Qwen/Qwen3-32B", "com.amd.aim.model.canonicalName": "Qwen/Qwen3-32B", "org.opencontainers.image.source": "https://github.com/silogen/aim-build", "org.opencontainers.image.vendor": "AMD", "org.opencontainers.image.authors": "", "org.opencontainers.image.created": "2026-02-26T12:28:37Z", "org.opencontainers.image.version": "", "org.opencontainers.image.licenses": "Apache-2.0, MIT", "org.opencontainers.image.ref.name": "ubuntu", "org.opencontainers.image.revision": "211ec31d00c955e004caa61ac97a616ca8cf9047", "org.opencontainers.image.description": "32.8B parameter dense language model with dual thinking modes and multilingual support.", "org.opencontainers.image.documentation": "", "com.amd.aim.model.recommendedDeployments": "[{'gpuModel': 'MI300X', 'gpuCount': 1, 'precision': 'fp16', 'metric': 'latency', 'description': 'Optimized for latency on MI300X using fp16 precision'}, {'gpuModel': 'MI300X', 'gpuCount': 1, 'precision': 'fp16', 'metric': 'throughput', 'description': 'Optimized for throughput on MI300X using fp16 precision'}, {'gpuModel': 'MI325X', 'gpuCount': 1, 'metric': 'latency', 'description': 'Optimized for latency on MI325X using fp16 precision', 'profileId': 'vllm-mi325x-fp16-tp1-latency'}, {'gpuModel': 'MI325X', 'gpuCount': 1, 'metric': 'throughput', 'description': 'Optimized for throughput on MI325X using fp16 precision', 'profileId': 'vllm-mi325x-fp16-tp1-throughput'}, {'gpuModel': 'MI350X', 'gpuCount': 1, 'precision': 'fp16', 'metric': 'latency', 'description': 'Optimized for latency on MI350X using fp16 precision'}, {'gpuModel': 'MI350X', 'gpuCount': 2, 'precision': 'fp16', 'metric': 'throughput', 'description': 'Optimized for throughput on MI350X using fp16 precision'}, {'gpuModel': 'MI355X', 'gpuCount': 1, 'precision': 'fp16', 'metric': 'latency', 'description': 'Optimized for latency on MI355X using fp16 precision'}, {'gpuModel': 'MI355X', 'gpuCount': 1, 'precision': 'fp16', 'metric': 'throughput', 'description': 'Optimized for throughput on MI355X using fp16 precision'}]"}	amdenterpriseai-aim-qwen-qwen3-32b-0.10.0-8ad331	amdenterpriseai/aim-qwen-qwen3-32b:0.10.0	Ready
aa23a100-02c2-4187-ab24-385a32b23aac	2026-03-17 12:31:36.107973+00	2026-03-17 12:35:04.380909+00	system	system	{"maintainer": "dl.mlsedevops@amd.com", "com.amd.aim.title": "Llama 3.2 1B Instruct", "com.amd.aim.model.tags": "text-generation, chat, instruction", "com.amd.aim.model.source": "https://huggingface.co/meta-llama/Llama-3.2-1B-Instruct", "com.amd.aim.release.notes": "", "com.amd.aim.model.variants": "meta-llama/Llama-3.2-1B-Instruct", "com.amd.aim.model.publisher": "Meta", "com.amd.aim.description.full": "Llama 3.2 1B Instruct is part of the Meta Llama 3.2 collection of multilingual large language models, available in 1B and 3B sizes. It is a 1.23 billion parameter auto-regressive language model using an optimized transformer architecture with Grouped-Query Attention (GQA) and shared embeddings. The model incorporates knowledge distillation from Llama 3.1 8B and 70B models during pretraining, with pruning applied to recover performance. The instruction-tuned version uses supervised fine-tuning (SFT), rejection sampling (RS), and direct preference optimization (DPO) for alignment. It supports multilingual dialogue across 8 languages (English, German, French, Italian, Portuguese, Hindi, Spanish, and Thai) with a 128k token context length. Pre-trained on up to 9 trillion tokens with a knowledge cutoff of December 2023. Intended for assistant-like chat, agentic retrieval, summarization, and on-device applications.", "com.amd.aim.hfToken.required": "True", "org.opencontainers.image.title": "meta-llama/Llama-3.2-1B-Instruct", "com.amd.aim.model.canonicalName": "meta-llama/Llama-3.2-1B-Instruct", "org.opencontainers.image.source": "https://github.com/silogen/aim-build", "org.opencontainers.image.vendor": "AMD", "org.opencontainers.image.authors": "", "org.opencontainers.image.created": "2026-02-26T12:43:16Z", "org.opencontainers.image.version": "", "org.opencontainers.image.licenses": "llama3.2, MIT", "org.opencontainers.image.ref.name": "ubuntu", "org.opencontaine