66cad58b-3104-485d-ae39-31539ea9ec59	values.yaml	metadata:\n  annotations:\n    pvc.silogen.ai/user-pvc-auto-create: "true"\n    pvc.silogen.ai/user-pvc-size: "2Gi"\n    pvc.silogen.ai/user-pvc-storage-class-name: "multinode"\n    pvc.silogen.ai/user-pvc-uid: "{{ .Values.metadata.user_id }}"\n  labels: {}\n  project_id: silogen\n  user_id: user\n  workload_id: # defaults to the release name\n\nimage: "rocm/pytorch:rocm7.1.1_ubuntu24.04_py3.12_pytorch_release_2.8.0"\nmodel: Comfy-Org/flux1-dev\ntag: fp8\n\nimagePullPolicy: Always\nimagePullSecrets: []\ngpus: 1\ncpu_per_gpu: 16\nmemory_per_gpu: 128\n\nenv_vars:\n  BUCKET_STORAGE_HOST: http://minio.minio-tenant-default.svc.cluster.local:80\n  BUCKET_STORAGE_ACCESS_KEY:\n    name: minio-credentials\n    key: minio-access-key\n  BUCKET_STORAGE_SECRET_KEY:\n    name: minio-credentials\n    key: minio-secret-key\n  PIP_DEPS: ""\n  COMFYUI_PATH: "/workload/{{ .Values.metadata.user_id }}/ComfyUI"\n  # MODEL_BIN_URL: "https://huggingface.co/Comfy-Org/Lumina_Image_2.0_Repackaged/resolve/main/all_in_one/lumina_2.safetensors"\n\nstorage:\n  ephemeral:\n    quantity: 200Gi\n    storageClassName: mlstorage\n    accessModes:\n      - ReadWriteOnce\n  dshm:\n    sizeLimit: 32Gi\n\ndeployment:\n  ports:\n    http: 8188\n\n# startupProbe - checks if the container has successfully started. It disables liveness and readiness probes until it succeeds, useful for slow-starting applications.\n# livenessProbe - checks if the container is still alive. If it fails, Kubernetes restarts the container to recover from failure.\n# readinessProbe - checks if the container is ready to serve traffic. If it fails, the container is removed from the service's endpoints but remains running.\n# ref: https://kubernetes.io/docs/tasks/configure-pod-container/configure-liveness-readiness-startup-probes/\nstartupProbe:\n  httpGet:\n    path: /queue\n    port: http\n  failureThreshold: 60 # 60 x 10s => allow for 10 minutes startup time\n  periodSeconds: 10\nlivenessProbe:\n  httpGet:\n    path: /queue\n    port: http\nreadinessProbe:\n  httpGet:\n    path: /queue\n    port: http\n\n# kaiwo settings (if enabled, use kaiwo CRDs to have kaiwo operator manage the workload)\nkaiwo:\n  enabled: false\n\nhttp_route:\n  enabled: false\n\ningress:\n  enabled: false\n\npersistent_storage:\n  enabled: false\n  volumes:\n    pvc-user:\n      pvc_name: "pvc-{{ .Values.metadata.user_id }}"\n      mount_path: "/workload/{{ .Values.metadata.user_id }}"\n	73017e6d-e623-4f5e-8744-96895d0b098b	2026-03-17 12:30:30.702792+00	2026-03-17 12:30:30.702793+00	system	system
938c091a-9b81-401a-b479-6a6f687d6f01	templates/_helpers.tpl	# Base URL helper\n{{- define "httpRoute.baseUrl" -}}\n{{- $projectId := default "project_id" .Values.metadata.project_id -}}\n{{- $userId := default "user_id" .Values.metadata.user_id -}}\n{{- $workloadId := default (include "release.fullname" .) .Values.metadata.workload_id -}}\n{{- printf "/%s/%s/%s" $projectId $userId $workloadId }}\n{{- end -}}\n\n# Release name helper\n{{- define "release.name" -}}\n{{- default .Chart.Name .Values.nameOverride | trunc 63 | trimSuffix "-" -}}\n{{- end -}}\n\n# Release fullname helper\n{{- define "release.fullname" -}}\n{{- $currentTime := now | date "20060102-1504" -}}\n{{- if .Values.fullnameOverride -}}\n{{- .Values.fullnameOverride | trunc 63 | trimSuffix "-" -}}\n{{- else -}}\n{{- if ne .Release.Name "release-name" -}}\n{{- include "release.name" . }}-{{ .Release.Name | trunc 63 | trimSuffix "-" -}}\n{{- else -}}\n{{- include "release.name" . }}-{{ $currentTime | lower | trunc 63 | trimSuffix "-" -}}\n{{- end -}}\n{{- end -}}\n{{- end -}}\n\n# Container resources helper\n{{- define "container.resources" -}}\nrequests:\n  memory: "{{ max (mul .Values.gpus .Values.memory_per_gpu) 4 }}Gi"\n  cpu: "{{ max (mul .Values.gpus .Values.cpu_per_gpu) 1 }}"\n  {{- if .Values.gpus }}\n  amd.com/gpu: "{{ .Values.gpus }}"\n  {{- end }}\nlimits:\n  memory: "{{ max (mul .Values.gpus .Values.memory_per_gpu) 4 }}Gi"\n  cpu: "{{ max (mul .Values.gpus .Values.cpu_per_gpu) 1 }}"\n  {{- if .Values.gpus }}\n  amd.com/gpu: "{{ .Values.gpus }}"\n  {{- end }}\n{{- end -}}\n\n# Container environment variables helper\n{{- define "container.env" -}}\n{{- range $key, $value := .Values.env_vars }}\n{{- if (typeIs "string" $value) }}\n- name: {{ $key }}\n  value: {{ tpl $value $ | quote }}\n{{- else }}\n- name: {{ $key }}\n  valueFrom:\n    secretKeyRef:\n      name: {{ $value.name }}\n      key: {{ $value.key }}\n{{- end }}\n{{- end }}\n{{- end -}}\n\n# Container volume mounts helper\n{{- define "container.volumeMounts" -}}\n- mountPath: /workload\n  name: ephemeral-storage\n- mountPath: /workload/mount\n  name: workload-mount\n- mountPath: /dev/shm\n  name: dshm\n{{- if .Values.persistent_storage.enabled }}\n{{- range $key, $value := .Values.persistent_storage.volumes }}\n- mountPath: {{ tpl $value.mount_path $ }}\n  name: {{ $key }}\n{{- end }}\n{{- end }}\n{{- end -}}\n\n# Container volumes helper\n{{- define "container.volumes" -}}\n{{- if .Values.storage.ephemeral.storageClassName -}}\n- ephemeral:\n    volumeClaimTemplate:\n      spec:\n        {{- if .Values.storage.ephemeral.accessModes }}\n        accessModes: {{ .Values.storage.ephemeral.accessModes }}\n        {{- else }}\n        accessModes:\n          - ReadWriteOnce\n        {{- end }}\n        resources:\n          requests:\n            storage: {{ .Values.storage.ephemeral.quantity }}\n        storageClassName: {{ .Values.storage.ephemeral.storageClassName }}\n  name: ephemeral-storage\n{{- else }}\n- emptyDir: {}\n  name: ephemeral-storage\n  sizeLimit: {{ .Values.storage.ephemeral.quantity }}\n{{- end }}\n- emptyDir:\n    medium: Memory\n    sizeLimit: {{ .Values.storage.dshm.sizeLimit }}\n  name: dshm\n- configMap:\n    name: {{ include "release.fullname" . }}\n  name: workload-mount\n{{- if .Values.persistent_storage.enabled }}\n{{- range $key, $value := .Values.persistent_storage.volumes }}\n- persistentVolumeClaim:\n    claimName: {{ tpl $value.pvc_name $ }}\n  name: {{ $key }}\n{{- end }}\n{{- end }}\n{{- end -}}\n	73017e6d-e623-4f5e-8744-96895d0b098b	2026-03-17 12:30:30.702795+00	2026-03-17 12:30:30.702796+00	system	system
bceb1bbc-cca7-43d6-8152-037ad47825ef	templates/ingress.yaml	{{- if .Values.ingress.enabled -}}\napiVersion: networking.k8s.io/v1\nkind: Ingress\nmetadata:\n  name: {{ include "release.fullname" . }}\n  annotations:\n    nginx.ingress.kubernetes.io/enable-websocket: "true"\n    nginx.ingress.kubernetes.io/proxy-connect-timeout: "3600"\n    nginx.ingress.kubernetes.io/proxy-http-version: "1.1"\n    nginx.ingress.kubernetes.io/proxy-read-timeout: "3600"\n    nginx.ingress.kubernetes.io/proxy-send-timeout: "3600"\n    nginx.ingress.kubernetes.io/proxy-set-header-Origin: ""\n    nginx.ingress.kubernetes.io/rewrite-target: /$2\n    nginx.ingress.kubernetes.io/use-regex: "true"\nspec:\n  rules:\n  - http:\n      paths:\n      - backend:\n          service:\n            name: {{ include "release.fullname" . }}\n            port:\n              number: 80\n        path: {{ include "httpRoute.baseUrl" . }}(/|$)(.*)\n        pathType: ImplementationSpecific\n{{- end -}}\n	73017e6d-e623-4f5e-8744-96895d0b098b	2026-03-17 12:30:30.702799+00	2026-03-17 12:30:30.702799+00	system	system
5b9868ce-6c72-41d6-8e03-d0eccc394534	templates/deployment.yaml	{{- define "deployment" -}}\napiVersion: apps/v1\nkind: Deployment\nmetadata:\n  name: {{ include "release.fullname" . }}\n  labels:\n    app: {{ include "release.fullname" . }}\n    {{- range $key, $value := .Values.metadata.labels }}\n    {{ $key }}: {{ $value | quote }}\n    {{- end }}\nspec:\n  replicas: 1\n  selector:\n    matchLabels:\n      app: {{ include "release.fullname" . }}\n  template:\n    metadata:\n      annotations:\n        {{- range $key, $value := .Values.metadata.annotations }}\n        {{ $key }}: {{ tpl $value $ | quote }}\n        {{- end }}\n      labels:\n        app: {{ include "release.fullname" . }}\n    spec:\n      {{- if .Values.imagePullSecrets }}\n      imagePullSecrets:\n        {{- range .Values.imagePullSecrets }}\n        - name: {{ . }}\n        {{- end }}\n      {{- end }}\n      containers:\n        - name: {{ .Chart.Name }}\n          args:\n          - |\n            {{- include "entrypoint" . | nindent 12 }}\n          command: ["sh", "-c"]\n          {{- if .Values.env_vars }}\n          env:\n            {{- include "container.env" . | nindent 12 }}\n          {{- end }}\n          image: {{ .Values.image | quote}}\n          imagePullPolicy: {{ default "Always" .Values.imagePullPolicy | quote }}\n          {{- if .Values.livenessProbe }}\n          livenessProbe:\n            {{- .Values.livenessProbe | toYaml | nindent 12 -}}\n          {{- end }}\n          ports:\n            {{- range $key, $value := .Values.deployment.ports }}\n            - name: {{ $key }}\n              containerPort: {{ $value }}\n            {{- end }}\n          {{- if .Values.readinessProbe }}\n          readinessProbe:\n            {{- .Values.readinessProbe | toYaml | nindent 12 -}}\n          {{- end }}\n          resources:\n            {{- include "container.resources" . | nindent 12 }}\n          {{- if .Values.startupProbe }}\n          startupProbe:\n            {{- .Values.startupProbe | toYaml | nindent 12 -}}\n          {{- end }}\n          volumeMounts:\n            {{- include "container.volumeMounts" . | nindent 12 }}\n      volumes:\n        {{- include "container.volumes" . | nindent 8 }}\n{{- end -}}\n\n{{- define "deployment_stripped" -}}\n{{- $deployment := include "deployment" . | fromYaml }}\n{{- $ := unset $deployment "metadata" }}\n{{- $ := unset $deployment.spec.template "metadata" }}\n{{- $deployment | toYaml }}\n{{- end -}}\n\n{{- define "deployment_wrapped_with_kaiwoservice" -}}\napiVersion: kaiwo.silogen.ai/v1alpha1\nkind: KaiwoService\nmetadata:\n  name: {{ include "release.fullname" . }}\n  labels:\n    app: {{ include "release.fullname" . }}\n    {{- range $key, $value := .Values.metadata.labels }}\n    {{ $key }}: {{ $value | quote }}\n    {{- end }}\nspec:\n  deployment:\n    {{- include "deployment" . | nindent 4 }}\n{{- end -}}\n\n{{- if .Values.kaiwo.enabled -}}\n{{- include "deployment_wrapped_with_kaiwoservice" . }}\n{{- else -}}\n{{- include "deployment" . }}\n{{- end -}}\n	73017e6d-e623-4f5e-8744-96895d0b098b	2026-03-17 12:30:30.702802+00	2026-03-17 12:30:30.702802+00	system	system
