7277e4af-703f-4237-9c6b-cd71cd6f608e	templates/_entrypoint.tpl	{{- define "minio.setup" -}}\n{{- $model := trimPrefix "s3://" .Values.model | trimSuffix "/" -}}\n{{- $minioModel := printf "minio-host/%s" $model -}}\n{{- $localModel := printf "/workload/%s/ComfyUI/models/checkpoints/%s" (.Values.metadata.user_id) (base $model) -}}\necho '--------------------------------------------'\necho 'Installing minio client'\necho '--------------------------------------------'\ncurl https://dl.min.io/client/mc/release/linux-amd64/mc \\\n      --create-dirs \\\n      -o /minio-binaries/mc\nchmod +x /minio-binaries/mc\nexport PATH="${PATH}:/minio-binaries/"\nmc alias set minio-host ${BUCKET_STORAGE_HOST} ${BUCKET_STORAGE_ACCESS_KEY} ${BUCKET_STORAGE_SECRET_KEY}\necho '--------------------------------------------'\necho 'Downloading the model from S3: {{ .Values.model }}'\necho '--------------------------------------------'\nmkdir -p /workload/{{ .Values.metadata.user_id }}/ComfyUI/models/checkpoints/\nmc cp --recursive {{$minioModel}} {{$localModel}} || { echo "Model copy from MinIO failed"; exit 1; }\n{{- end }}\n\n{{- define "comfyui.setup" }}\necho '--------------------------------------------'\necho 'Setting up ComfyUI environment'\necho '--------------------------------------------'\napt-get update && apt-get install -y git\npip install comfy-cli huggingface_hub[hf_transfer] hiredis $PIP_DEPS\nyes | comfy --workspace=$COMFYUI_PATH install --skip-torch-or-directml --amd --restore\necho '--------------------------------------------'\n{{- end }}\n\n{{- define "comfyui.download_model" }}\n{{- if not (hasPrefix "s3://" .Values.model) }}\necho '--------------------------------------------'\necho 'Downloading model from HuggingFace: {{ .Values.model }}'\necho '--------------------------------------------'\nhf download {{ .Values.model }} --local-dir $COMFYUI_PATH/models/checkpoints {{- if .Values.tag }} --include *{{ .Values.tag }}*safetensors{{- end }}\n\n{{- end }}\n{{- end }}\n\n{{- define "comfyui.start" }}\necho '--------------------------------------------'\necho 'Starting ComfyUI'\necho '--------------------------------------------'\n\nif [ -z "$MODEL_BIN_URL" ]; then\n    echo "MODEL_BIN_URL is not set, skipped downloading."\nelse\n    echo "Downloading model from URL: $MODEL_BIN_URL"\n    mkdir -p $COMFYUI_PATH/models/checkpoints/\n    env -C $COMFYUI_PATH/models/checkpoints/ curl -LO ${MODEL_BIN_URL} || { echo "Model download failed"; exit 1; }\nfi\n\ncomfy --workspace=$COMFYUI_PATH launch -- --listen 0.0.0.0\n{{- end }}\n\n{{ define "entrypoint" }}\n{{- include "comfyui.setup" . }}\n\n{{- if and .Values.model (ne .Values.model "") }}\n{{- if (hasPrefix "s3://" (toString .Values.model)) }}\n{{- include "minio.setup" . }}\n{{- else }}\n{{- include "comfyui.download_model" . }}\n{{- end }}\n{{- end }}\n\n{{- include "comfyui.start" . }}\n{{- end }}\n	73017e6d-e623-4f5e-8744-96895d0b098b	2026-03-17 12:30:30.702808+00	2026-03-17 12:30:30.702808+00	system	system
fba5bb72-bcfe-4312-8fcf-18c72c8eeb74	templates/httproute.yaml	{{- if .Values.http_route.enabled -}}\napiVersion: gateway.networking.k8s.io/v1\nkind: HTTPRoute\nmetadata:\n  name: {{ include "release.fullname" . }}\nspec:\n  parentRefs:\n    - name: https\n      namespace: kgateway-system\n  rules:\n    - backendRefs:\n        - name:  {{ include "release.fullname" . }}\n          port: 80\n      matches:\n      - path:\n          type: PathPrefix\n          value: {{ include "httpRoute.baseUrl" . }}\n      filters:\n        - type: URLRewrite\n          urlRewrite:\n            path:\n              type: ReplacePrefixMatch\n              replacePrefixMatch: /\n{{- end -}}\n	73017e6d-e623-4f5e-8744-96895d0b098b	2026-03-17 12:30:30.702811+00	2026-03-17 12:30:30.702811+00	system	system
60067fc0-58f3-41bd-898b-b49b597476e1	templates/configmap.yaml	apiVersion: v1\nkind: ConfigMap\nmetadata:\n  name: {{ include "release.fullname" . }}\ndata:\n{{- $files := .Files }}\n{{- range $path, $_ := .Files.Glob "mount/*" }}\n  {{ $key := $path | trimPrefix "mount/" }}\n  {{- $key }}: |\n{{ $files.Get $path | indent 4 }}\n{{- end }}\n	73017e6d-e623-4f5e-8744-96895d0b098b	2026-03-17 12:30:30.702814+00	2026-03-17 12:30:30.702814+00	system	system
3cb281d3-5bff-49f5-a017-0667adf8c671	Chart.yaml	apiVersion: v2\nname: dev-tracking-mlflow\ndescription: A Helm chart for deploying MLflow tracking server\nversion: 0.0.1\n	369323da-5438-4d7e-808e-5ecd7c019aa4	2026-03-17 12:30:30.731973+00	2026-03-17 12:30:30.731975+00	system	system
ea3989be-03cc-431b-a1eb-eeb477ed8086	values.yaml	metadata:\n  labels: {}\n  project_id: silogen\n  user_id: user # set to empty or null for project-wide workloads\n  workload_id: # defaults to the release name\n\nimage: ghcr.io/mlflow/mlflow:v2.22.0\nimagePullPolicy: Always\nimagePullSecrets: []\n\ngpus: 0\n# also default when no gpu assigned\nmemory_per_gpu: 128 # Gi\ncpu_per_gpu: 8\n\nenv_vars:\n  # https://mlflow.org/docs/latest/api_reference/python_api/mlflow.environment_variables.html\n  MLFLOW_ARTIFACTS_DESTINATION: "s3://default-bucket/mlflow/artifacts"\n  MLFLOW_S3_ENDPOINT_URL: http://minio.minio-tenant-default.svc.cluster.local:80\n  # MLFLOW_S3_IGNORE_TLS: "true"\n  AWS_ACCESS_KEY_ID:\n    name: minio-credentials\n    key: minio-access-key\n  AWS_SECRET_ACCESS_KEY:\n    name: minio-credentials\n    key: minio-secret-key\n\nstorage:\n  ephemeral:\n    quantity: 128Gi\n    storageClassName: mlstorage\n    accessModes:\n      - ReadWriteOnce\n  dshm:\n    sizeLimit: 16Gi\n\nbackendStore:\n  type: sqlite # Options: sqlite, postgres, mysql\n  # For sqlite\n  dbpath: "/workload/mlflow.db"\n  # For postgres/mysql\n  host: ""\n  port: ""\n  database: ""\n  driver: ""\n  # Secret configuration for database credentials (required for postgres/mysql)\n  # To use secrets, create a Kubernetes secret with username and password keys:\n  # kubectl create secret generic mlflow-db-credentials--from-literal=username=myuser --from-literal=password=mypassword\n  secret:\n    name: "mlflow-db-credentials" # Name of the secret containing database credentials (e.g., "mlflow-db-credentials")\n    userKey: "username" # Key in the secret for username (default: username)\n    passwordKey: "password" # Key in the secret for password (default: password)\n\ndeployment:\n  ports:\n    http: 8080\n\n# startupProbe - checks if the container has successfully started. It disables liveness and readiness probes until it succeeds, useful for slow-starting applications.\n# livenessProbe - checks if the container is still alive. If it fails, Kubernetes restarts the container to recover from failure.\n# readinessProbe - checks if the container is ready to serve traffic. If it fails, the container is removed from the service's endpoints but remains running.\n# ref: https://kubernetes.io/docs/tasks/configure-pod-container/configure-liveness-readiness-startup-probes/\nstartupProbe:\n  httpGet:\n    path: /health\n    port: http\n  failureThreshold: 20\nlivenessProbe:\n  httpGet:\n    path: /health\n    port: http\nreadinessProbe:\n  httpGet:\n    path: /health\n    port: http\n\n# Commands to run before starting the MLFlow server.\n# entrypoint: |\n#   tail -f /dev/null\n\n# kaiwo settings (if enabled, use kaiwo CRDs to have kaiwo operator manage the workload)\nkaiwo:\n  enabled: false\n\nhttp_route:\n  enabled: false\n\ningress:\n  enabled: false\n\npersistent_storage:\n  enabled: false\n  volumes:\n    pvc-user:\n      pvc_name: "pvc-user-{{ .Values.metadata.user_id }}"\n      mount_path: "/workload/{{ .Values.metadata.user_id }}"\n	369323da-5438-4d7e-808e-5ecd7c019aa4	2026-03-17 12:30:30.731978+00	2026-03-17 12:30:30.731978+00	system	system
2a1fcb44-e303-455a-a0b6-b3e59833cbb6	mount/install_minio.sh	#!/bin/bash\n\necho '--------------------------------------------'\necho 'Installing MinIO Client'\necho '--------------------------------------------'\n\n# Download MinIO client binary\napt-get update && apt-get install -y curl\ncurl -s https://dl.min.io/client/mc/release/linux-amd64/mc \\\n    --create-dirs \\\n    -o /usr/local/bin/mc\n\n# Make the binary executable\nchmod +x /usr/local/bin/mc\n\n# Configure MinIO alias\nmc alias set minio "${MLFLOW_S3_ENDPOINT_URL}" "${AWS_ACCESS_KEY_ID}" "${AWS_SECRET_ACCESS_KEY}"\n\necho '--------------------------------------------'\necho 'MinIO Client Installed!'\necho '--------------------------------------------'\n\n# check if MLFLOW_ARTIFACTS_DESTINATION starts with s3://\nif [[ "${MLFLOW_ARTIFACTS_DESTINATION}" == s3://* ]]; then\n    echo '--------------------------------------------'\n    echo 'Configuring MinIO for MLFLOW_ARTIFACTS_DESTINATION'\n    echo '--------------------------------------------'\n\n    # Extract bucket name from MLFLOW_ARTIFACTS_DESTINATION\n    BUCKET_NAME=${MLFLOW_ARTIFACTS_DESTINATION#s3://}\n\n    # Create the bucket if it does not exist\n    if ! mc mb minio/"${BUCKET_NAME}"; then\n        # Check if the failure was because bucket already exists\n        if mc ls minio/"${BUCKET_NAME}" >/dev/null 2>&1; then\n            echo "Bucket ${BUCKET_NAME} already exists."\n        else\n            echo "Error: Failed to create bucket ${BUCKET_NAME} and bucket does not exist."\n            exit 1\n        fi\n    fi\n\n    echo '--------------------------------------------'\n    echo 'MinIO configured for MLFLOW_ARTIFACTS_DESTINATION!'\n    echo '--------------------------------------------'\nfi\n	369323da-5438-4d7e-808e-5ecd7c019aa4	2026-03-17 12:30:30.731982+00	2026-03-17 12:30:30.731982+00	system	system
6281a920-9a4d-44a7-a4a8-a07df98b59c2	templates/_helpers.tpl	# Base URL helper\n{{- define "httpRoute.baseUrl" -}}\n{{- $projectId := default "project_id" .Values.metadata.project_id -}}\n{{- $userId := .Values.metadata.user_id -}}\n{{- $workloadId := default (include "release.fullname" .) .Values.metadata.workload_id -}}\n{{- if or (eq $userId "") (eq $userId nil) }}\n{{- printf "/%s/%s" $projectId $workloadId }}\n{{- else -}}\n{{- printf "/%s/%s/%s" $projectId $userId $workloadId }}\n{{- end -}}\n{{- end -}}\n\n# Release name helper\n{{- define "release.name" -}}\n{{- default .Chart.Name .Values.nameOverride | trunc 63 | trimSuffix "-" -}}\n{{- end -}}\n\n# Release fullname helper\n{{- define "release.fullname" -}}\n{{- $currentTime := now | date "20060102-1504" -}}\n{{- if .Values.fullnameOverride -}}\n{{- .Values.fullnameOverride | trunc 63 | trimSuffix "-" -}}\n{{- else -}}\n{{- if ne .Release.Name "release-name" -}}\n{{- include "release.name" . }}-{{ .Release.Name | trunc 63 | trimSuffix "-" -}}\n{{- else -}}\n{{- include "release.name" . }}-{{ $currentTime | lower | trunc 63 | trimSuffix "-" -}}\n{{- end -}}\n{{- end -}}\n{{- end -}}\n\n# Container resources helper\n{{- define "container.resources" -}}\nrequests:\n  memory: "{{ max (mul (max .Values.gpus 1) .Values.memory_per_gpu) 4 }}Gi"\n  cpu: "{{ max (mul (max .Values.gpus 1)  .Values.cpu_per_gpu) 1 }}"\n  {{- if .Values.gpus }}\n  amd.com/gpu: "{{ .Values.gpus }}"\n  {{- end }}\nlimits:\n  memory: "{{ max (mul (max .Values.gpus 1) .Values.memory_per_gpu) 4 }}Gi"\n  cpu: "{{ max (mul (max .Values.gpus 1) .Values.cpu_per_gpu) 1 }}"\n  {{- if .Values.gpus }}\n  amd.com/gpu: "{{ .Values.gpus }}"\n  {{- end }}\n{{- end -}}\n\n# Container environment variables helper\n{{- define "container.env" -}}\n{{- range $key, $value := .Values.env_vars }}\n{{- if (typeIs "string" $value) }}\n- name: {{ $key }}\n  value: {{ $value | quote }}\n{{- else }}\n- name: {{ $key }}\n  valueFrom:\n    secretKeyRef:\n      name: {{ $value.name }}\n      key: {{ $value.key }}\n{{- end }}\n{{- end }}\n{{- end -}}\n\n# Container volume mounts helper\n{{- define "container.volumeMounts" -}}\n- mountPath: /workload\n  name: ephemeral-storage\n- mountPath: /workload/mount\n  name: workload-mount\n- mountPath: /dev/shm\n  name: dshm\n{{- if .Values.persistent_storage.enabled }}\n{{- range $key, $value := .Values.persistent_storage.volumes }}\n- mountPath: {{ tpl $value.mount_path $ }}\n  name: {{ $key }}\n{{- end }}\n{{- end }}\n{{- end -}}\n\n# Container volumes helper\n{{- define "container.volumes" -}}\n{{- if .Values.storage.ephemeral.storageClassName -}}\n- ephemeral:\n    volumeClaimTemplate:\n      spec:\n        {{- if .Values.storage.ephemeral.accessModes }}\n        accessModes: {{ .Values.storage.ephemeral.accessModes }}\n        {{- else }}\n        accessModes:\n          - ReadWriteOnce\n        {{- end }}\n        resources:\n          requests:\n            storage: {{ .Values.storage.ephemeral.quantity }}\n        storageClassName: {{ .Values.storage.ephemeral.storageClassName }}\n  name: ephemeral-storage\n{{- else }}\n- emptyDir: {}\n  name: ephemeral-storage\n  sizeLimit: {{ .Values.storage.ephemeral.quantity }}\n{{- end }}\n- emptyDir:\n    medium: Memory\n    sizeLimit: {{ .Values.storage.dshm.sizeLimit }}\n  name: dshm\n- configMap:\n    name: {{ include "release.fullname" . }}\n  name: workload-mount\n{{- if .Values.persistent_storage.enabled }}\n{{- range $key, $value := .Values.persistent_storage.volumes }}\n- persistentVolumeClaim:\n    claimName: {{ tpl $value.pvc_name $ }}\n  name: {{ $key }}\n{{- end }}\n{{- end }}\n{{- end -}}\n	369323da-5438-4d7e-808e-5ecd7c019aa4	2026-03-17 12:30:30.731985+00	2026-03-17 12:30:30.731985+00	system	system
c154fc08-c5e2-44a9-9d0f-802b5b297e6c	templates/ingress.yaml	{{- if .Values.ingress.enabled -}}\napiVersion: networking.k8s.io/v1\nkind: Ingress\nmetadata:\n  name: {{ include "release.fullname" . }}\n  annotations:\n    nginx.ingress.kubernetes.io/enable-websocket: "true"\n    nginx.ingress.kubernetes.io/proxy-connect-timeout: "3600"\n    nginx.ingress.kubernetes.io/proxy-http-version: "1.1"\n    nginx.ingress.kubernetes.io/proxy-read-timeout: "3600"\n    nginx.ingress.kubernetes.io/proxy-send-timeout: "3600"\n    nginx.ingress.kubernetes.io/proxy-set-header-Origin: ""\n    nginx.ingress.kubernetes.io/rewrite-target: /$2\n    nginx.ingress.kubernetes.io/use-regex: "true"\nspec:\n  rules:\n  - http:\n      paths:\n      - backend:\n          service:\n            name: {{ include "release.fullname" . }}\n            port:\n              number: 80\n        path: {{ include "httpRoute.baseUrl" . }}(/|$)(.*)\n        pathType: ImplementationSpecific\n{{- end -}}\n	369323da-5438-4d7e-808e-5ecd7c019aa4	2026-03-17 12:30:30.731987+00	2026-03-17 12:30:30.731988+00	system	system
225a94fc-e2eb-4ad6-b46b-7042a5467fd1	templates/deployment.yaml	{{- define "deployment" -}}\napiVersion: apps/v1\nkind: Deployment\nmetadata:\n  name: {{ include "release.fullname" . }}\n  labels:\n    app: {{ include "release.fullname" . }}\n    {{- range $key, $value := .Values.metadata.labels }}\n    {{ $key }}: {{ $value | quote }}\n    {{- end }}\nspec:\n  replicas: 1\n  selector:\n    matchLabels:\n      app: {{ include "release.fullname" . }}\n  template:\n    metadata:\n      annotations:\n        {{- range $key, $value := .Values.metadata.annotations }}\n        {{ $key }}: {{ tpl $value $ | quote }}\n        {{- end }}\n      labels:\n        app: {{ include "release.fullname" . }}\n    spec:\n      {{- if .Values.imagePullSecrets }}\n      imagePullSecrets:\n        {{- range .Values.imagePullSecrets }}\n        - name: {{ . }}\n        {{- end }}\n      {{- end }}\n      containers:\n      - name: {{ .Chart.Name }}\n        {{- if .Values.entrypoint }}\n        args:\n        - |\n          {{- .Values.entrypoint | nindent 12 }}\n        command: ["sh", "-c"]\n        {{- end }}\n        {{- if .Values.env_vars }}\n        env:\n          {{- include "container.env" . | nindent 12 }}\n        {{- end }}\n        image: {{ .Values.image | quote}}\n        imagePullPolicy: {{ default "Always" .Values.imagePullPolicy | quote }}\n        {{- if .Values.livenessProbe }}\n        livenessProbe:\n          {{- tpl (.Values.livenessProbe | toYaml) . | nindent 12 }}\n        {{- end }}\n        ports:\n          {{- range $key, $value := .Values.deployment.ports }}\n          - name: {{ $key }}\n            containerPort: {{ $value }}\n          {{- end }}\n        {{- if .Values.readinessProbe }}\n        readinessProbe:\n          {{- tpl (.Values.readinessProbe | toYaml) . | nindent 12 }}\n        {{- end }}\n        resources:\n          {{- include "container.resources" . | nindent 12 }}\n        {{- if .Values.startupProbe }}\n        startupProbe:\n          {{- tpl (.Values.startupProbe | toYaml) . | nindent 12 }}\n        {{- end }}\n        volumeMounts:\n          {{- include "container.volumeMounts" . | nindent 12 }}\n      volumes:\n        {{- include "container.volumes" . | nindent 8 }}\n{{- end -}}\n\n{{- define "deployment_stripped" -}}\n{{- $deployment := include "deployment" . | fromYaml }}\n{{- $ := unset $deployment "metadata" }}\n{{- $ := unset $deployment.spec.template "metadata" }}\n{{- $deployment | toYaml }}\n{{- end -}}\n\n{{- define "deployment_wrapped_with_kaiwoservice" -}}\napiVersion: kaiwo.silogen.ai/v1alpha1\nkind: KaiwoService\nmetadata:\n  name: {{ include "release.fullname" . }}\n  labels:\n    app: {{ include "release.fullname" . }}\n    {{- range $key, $value := .Values.metadata.labels }}\n    {{ $key }}: {{ $value | quote }}\n    {{- end }}\nspec:\n  deployment:\n    {{- include "deployment" . | nindent 4 }}\n{{- end -}}\n\n{{- if .Values.kaiwo.enabled -}}\n{{- include "deployment_wrapped_with_kaiwoservice" . }}\n{{- else -}}\n{{- include "deployment" . }}\n{{- end -}}\n	eb6b8668-f3a7-4394-a92e-4d4b7d418adf	2026-03-17 12:30:30.737475+00	2026-03-17 12:30:30.737475+00	system	system
7ab43687-a597-4ccb-9598-e68611441e05	templates/deployment.yaml	{{- define "deployment" -}}\napiVersion: apps/v1\nkind: Deployment\nmetadata:\n  name: {{ include "release.fullname" . }}\n  labels:\n    app: {{ include "release.fullname" . }}\n    {{- range $key, $value := .Values.metadata.labels }}\n    {{ $key }}: {{ $value | quote }}\n    {{- end }}\nspec:\n  replicas: 1\n  selector:\n    matchLabels:\n      app: {{ include "release.fullname" . }}\n  template:\n    metadata:\n      annotations:\n        {{- range $key, $value := .Values.metadata.annotations }}\n        {{ $key }}: {{ tpl $value $ | quote }}\n        {{- end }}\n      labels:\n        app: {{ include "release.fullname" . }}\n    spec:\n      {{- if .Values.imagePullSecrets }}\n      imagePullSecrets:\n        {{- range .Values.imagePullSecrets }}\n        - name: {{ . }}\n        {{- end }}\n      {{- end }}\n      containers:\n        - name: {{ .Chart.Name }}\n          command: ["sh", "-c"]\n          args:\n          - |\n            {{- if .Values.entrypoint }}\n            {{- .Values.entrypoint | nindent 12 }}\n            {{- end }}\n            # Start MLflow server\n            {{- if hasPrefix "s3" .Values.env_vars.MLFLOW_ARTIFACTS_DESTINATION }}\n            pip install boto3 && bash /workload/mount/install_minio.sh\n            {{- end }}\n            mlflow server \\\n              --host=0.0.0.0 \\\n              --port={{ .Values.deployment.ports.http }} \\\n            {{- if eq .Values.backendStore.type "sqlite" }}\n              --backend-store-uri=sqlite://{{ .Values.backendStore.dbpath }}\n            {{- else if eq .Values.backendStore.type "postgres" }}\n              --backend-store-uri=postgresql://$(DATABASE_USER):$(DATABASE_PASSWORD)@{{ .Values.backendStore.host }}:{{ .Values.backendStore.port }}/{{ .Values.backendStore.database }}\n            {{- else if eq .Values.backendStore.type "mysql" }}\n              --backend-store-uri=mysql+{{ .Values.backendStore.driver }}://$(DATABASE_USER):$(DATABASE_PASSWORD)@{{ .Values.backendStore.host }}:{{ .Values.backendStore.port }}/{{ .Values.backendStore.database }}\n            {{- end }}\n          {{- if or .Values.env_vars (and (ne .Values.backendStore.type "sqlite")) }}\n          env:\n            {{- if .Values.env_vars }}\n            {{- include "container.env" . | nindent 12 }}\n            {{- end }}\n            {{- if and (ne .Values.backendStore.type "sqlite") }}\n            - name: DATABASE_USER\n              valueFrom:\n                secretKeyRef:\n                  name: {{ .Values.backendStore.secret.name }}\n                  key: {{ .Values.backendStore.secret.userKey | default "username" }}\n            - name: DATABASE_PASSWORD\n              valueFrom:\n                secretKeyRef:\n                  name: {{ .Values.backendStore.secret.name }}\n                  key: {{ .Values.backendStore.secret.passwordKey | default "password" }}\n            {{- end }}\n          {{- end }}\n          image: {{ .Values.image | quote}}\n          imagePullPolicy: {{ default "Always" .Values.imagePullPolicy | quote }}\n          {{- if .Values.livenessProbe }}\n          livenessProbe:\n            {{- .Values.livenessProbe | toYaml | nindent 12 -}}\n          {{- end }}\n          ports:\n            {{- range $key, $value := .Values.deployment.ports }}\n            - name: {{ $key }}\n              containerPort: {{ $value }}\n            {{- end }}\n          {{- if .Values.readinessProbe }}\n          readinessProbe:\n            {{- .Values.readinessProbe | toYaml | nindent 12 -}}\n          {{- end }}\n          resources:\n            {{- include "container.resources" . | nindent 12 }}\n          {{- if .Values.startupProbe }}\n          startupProbe:\n            {{- .Values.startupProbe | toYaml | nindent 12 -}}\n          {{- end }}\n          volumeMounts:\n            {{- include "container.volumeMounts" . | nindent 12 }}\n      volumes:\n        {{- include "container.volumes" . | nindent 8 }}\n{{- end -}}\n\n{{- define "deployment_stripped" -}}\n{{- $deployment := include "deployment" . | fromYaml }}\n{{- $ := unset $deployment "metadata" }}\n{{- $ := unset $deployment.spec.template "metadata" }}\n{{- $deployment | toYaml }}\n{{- end -}}\n\n{{- define "deployment_wrapped_with_kaiwoservice" -}}\napiVersion: kaiwo.silogen.ai/v1alpha1\nkind: KaiwoService\nmetadata:\n  name: {{ include "release.fullname" . }}\n  labels:\n    app: {{ include "release.fullname" . }}\n    {{- range $key, $value := .Values.metadata.labels }}\n    {{ $key }}: {{ $value | quote }}\n    {{- end }}\nspec:\n  deployment:\n    {{- include "deployment" . | nindent 4 }}\n{{- end -}}\n\n{{- if .Values.kaiwo.enabled -}}\n{{- include "deployment_wrapped_with_kaiwoservice" . }}\n{{- else -}}\n{{- include "deployment" . }}\n{{- end -}}\n	369323da-5438-4d7e-808e-5ecd7c019aa4	2026-03-17 12:30:30.73199+00	2026-03-17 12:30:30.73199+00	system	system
9ad34a16-de6a-4715-b3ed-0e807ba4a0ab	templates/service.yaml	apiVersion: v1\nkind: Service\nmetadata:\n  name: {{ include "release.fullname" . }}\n  labels:\n    app: {{ include "release.fullname" . }}\nspec:\n  type: ClusterIP\n  ports:\n    {{ range $name, $port := .Values.deployment.ports }}\n    {{- if ne $name "http" }}\n    - name: {{ $name }}\n      port: {{ $port }}\n      targetPort: {{ $port }}\n    {{- else -}}\n    - name: {{ $name }}\n      port: 80\n      targetPort: {{ $port }}\n    {{- end }}\n    {{- end }}\n  selector:\n    app: {{ include "release.fullname" . }}\n	369323da-5438-4d7e-808e-5ecd7c019aa4	2026-03-17 12:30:30.731993+00	2026-03-17 12:30:30.731993+00	system	system
