602e9697-823e-469a-8d95-6471ab019de9	Chart.yaml	apiVersion: v2\nname: dev-workspace-vscode\ndescription: A Helm chart for deploying Visual Studio Code\nversion: 0.0.1\n	0538bf15-b13b-4c5b-988a-2d44a596e2ed	2026-03-17 12:30:30.743515+00	2026-03-17 12:30:30.743517+00	system	system
90e20db6-0a3a-4459-805c-c5c21a539769	values.yaml	metadata:\n  annotations: {}\n  labels: {}\n  project_id: silogen\n  user_id: user\n  workload_id: # defaults to the release name\n\n# PVC annotations for persistent storage (only applied when persistent_storage.enabled=true)\npvc_annotations:\n  pvc.silogen.ai/user-pvc-auto-create: "true"\n  pvc.silogen.ai/user-pvc-size: "2Gi"\n  pvc.silogen.ai/user-pvc-storage-class-name: "multinode"\n  pvc.silogen.ai/user-pvc-uid: "{{ .Values.metadata.user_id }}"\n\nimage: rocm/pytorch:rocm7.1.1_ubuntu24.04_py3.12_pytorch_release_2.8.0\nimagePullPolicy: Always\nimagePullSecrets: []\ngpus: 1\nmemory_per_gpu: 128 # Gi\ncpu_per_gpu: 4\n\nenv_vars:\n  BUCKET_STORAGE_HOST: http://minio.minio-tenant-default.svc.cluster.local:80\n  BUCKET_STORAGE_ACCESS_KEY:\n    name: minio-credentials\n    key: minio-access-key\n  BUCKET_STORAGE_SECRET_KEY:\n    name: minio-credentials\n    key: minio-secret-key\n  VSCODE_CONFIG_DIR: "/workload/{{ .Values.metadata.user_id }}/.vscode-server"\n\nstorage:\n  ephemeral:\n    quantity: 128Gi\n    storageClassName: mlstorage\n    accessModes:\n      - ReadWriteOnce\n  dshm:\n    sizeLimit: 16Gi\n\ndeployment:\n  ports:\n    http: 8080\n\n# startupProbe - checks if the container has successfully started. It disables liveness and readiness probes until it succeeds, useful for slow-starting applications.\n# livenessProbe - checks if the container is still alive. If it fails, Kubernetes restarts the container to recover from failure.\n# readinessProbe - checks if the container is ready to serve traffic. If it fails, the container is removed from the service's endpoints but remains running.\n# ref: https://kubernetes.io/docs/tasks/configure-pod-container/configure-liveness-readiness-startup-probes/\nstartupProbe:\n  httpGet:\n    path: /healthz\n    port: http\n  failureThreshold: 60\n  periodSeconds: 10\nlivenessProbe:\n  httpGet:\n    path: /healthz\n    port: http\nreadinessProbe:\n  httpGet:\n    path: /healthz\n    port: http\n\nentrypoint: |\n  bash /workload/mount/install_s3_clients.sh\n  curl -fsSL https://code-server.dev/install.sh | sh\n\n  # Set up persistent VSCode configuration directory using environment variable\n  VSCODE_USER_DIR="$VSCODE_CONFIG_DIR/code-server/User"\n\n  # Create directory structure if it doesn't exist\n  mkdir -p "$VSCODE_USER_DIR"\n  mkdir -p "$VSCODE_CONFIG_DIR/code-server/extensions"\n  mkdir -p "$VSCODE_CONFIG_DIR/code-server/logs"\n\n  # Copy default settings only if user settings don't exist (preserve user customizations)\n  if [ ! -f "$VSCODE_USER_DIR/settings.json" ]; then\n    cp /workload/mount/default_settings.json "$VSCODE_USER_DIR/settings.json"\n    sed -i "s|__PYTHON_PATH__|$(which python)|" "$VSCODE_USER_DIR/settings.json"\n  fi\n\n  # Set environment variables for code-server to use persistent directories\n  export XDG_DATA_HOME="$VSCODE_CONFIG_DIR"\n  export XDG_CONFIG_HOME="$VSCODE_CONFIG_DIR"\n\n  # Install extensions (these will be stored persistently)\n  curl -L -o /tmp/aws-s3-vscode-extension-1.8.5.vsix https://github.com/necatiarslan/aws-s3/raw/refs/heads/main/vsix/aws-s3-vscode-extension-1.8.5.vsix &&\n  code-server --install-extension /tmp/aws-s3-vscode-extension-1.8.5.vsix\n  code-server --install-extension ms-python.python\n  code-server --install-extension GitHub.vscode-pull-request-github\n  code-server --install-extension ms-kubernetes-tools.vscode-kubernetes-tools\n\n  # Start code-server with persistent configuration\n  code-server --auth none --bind-addr 0.0.0.0:8080\n\n# kaiwo settings (if enabled, use kaiwo CRDs to have kaiwo operator manage the workload)\nkaiwo:\n  enabled: false\n\nhttp_route:\n  enabled: false\n\ningress:\n  enabled: false\n\n# Persistent storage configuration for VSCode settings, extensions, and workspace data\n# When enabled: PVC will be created and mounted, VSCode data persists across pod restarts\n# When disabled: Only ephemeral storage is used, VSCode data is lost on pod restart\npersistent_storage:\n  enabled: false\n  volumes:\n    pvc-user:\n      pvc_name: "pvc-{{ .Values.metadata.user_id }}"\n      mount_path: "/workload/{{ .Values.metadata.user_id }}"\n	0538bf15-b13b-4c5b-988a-2d44a596e2ed	2026-03-17 12:30:30.74352+00	2026-03-17 12:30:30.743521+00	system	system
9924c08d-ad70-4820-b472-e43c886a522f	mount/install_s3_clients.sh	#!/bin/bash\n\necho '============================================'\necho 'Installing S3 Storage Clients (AWS CLI, MinIO, rclone)'\necho '============================================'\n\n# Install required dependencies\necho '--------------------------------------------'\necho 'Installing required dependencies (curl, unzip, rclone)'\necho '--------------------------------------------'\napt-get update && apt-get install -y curl unzip rclone\n\n# Function to install AWS CLI and boto3\ninstall_aws_cli() {\n    echo '--------------------------------------------'\n    echo 'Installing AWS CLI and boto3'\n    echo '--------------------------------------------'\n\n    # Download AWS cli binary\n    curl "https://awscli.amazonaws.com/awscli-exe-linux-x86_64.zip" --create-dirs -o "/workload/bin/awscliv2.zip"\n    unzip "/workload/bin/awscliv2.zip" -d /workload/bin/\n    /workload/bin/aws/install --bin-dir /usr/local/bin --install-dir /usr/local/aws-cli\n\n    # Configure AWS CLI with MinIO S3 settings\n    mkdir -p ~/.aws\n    cat > ~/.aws/config <<EOF\n[profile default]\naws_access_key_id = ${BUCKET_STORAGE_ACCESS_KEY}\naws_secret_access_key = ${BUCKET_STORAGE_SECRET_KEY}\nregion = us-east-1\nservices = minio-s3\n\n[services minio-s3]\ns3 =\n  endpoint_url = ${BUCKET_STORAGE_HOST}\nEOF\n\n    echo 'AWS CLI installed and configured!'\n    pip install boto3\n    echo 'boto3 installed!'\n}\n\n# Function to install MinIO Client\ninstall_minio_client() {\n    echo '--------------------------------------------'\n    echo 'Installing MinIO Client'\n    echo '--------------------------------------------'\n\n    # Download MinIO client binary\n    curl -s https://dl.min.io/client/mc/release/linux-amd64/mc \\\n        --create-dirs \\\n        -o /usr/local/bin/mc\n\n    # Make the binary executable\n    chmod +x /usr/local/bin/mc\n\n    # Configure MinIO alias\n    mc alias set minio "${BUCKET_STORAGE_HOST}" "${BUCKET_STORAGE_ACCESS_KEY}" "${BUCKET_STORAGE_SECRET_KEY}"\n\n    echo 'MinIO Client installed and configured!'\n}\n\n# Function to install rclone\ninstall_rclone() {\n    echo '--------------------------------------------'\n    echo 'Installing rclone'\n    echo '--------------------------------------------'\n\n    # Configure rclone with MinIO S3 settings\n    mkdir -p ~/.config/rclone\n    cat > ~/.config/rclone/rclone.conf <<EOF\n[minio]\ntype = s3\nprovider = Minio\nenv_auth = false\naccess_key_id = ${BUCKET_STORAGE_ACCESS_KEY}\nsecret_access_key = ${BUCKET_STORAGE_SECRET_KEY}\nregion = us-east-1\nendpoint = ${BUCKET_STORAGE_HOST}\nlocation_constraint =\nserver_side_encryption =\nEOF\n\n    echo 'rclone installed and configured!'\n}\n\n# Install all clients\ninstall_aws_cli\ninstall_minio_client\ninstall_rclone\n\necho '============================================'\necho 'All S3 Storage Clients Installed Successfully!'\necho '============================================'\n\n# Display comprehensive usage instructions\ncat << 'EOF'\n--------------------------------------------\nUSAGE INSTRUCTIONS:\n--------------------------------------------\n\nMinIO Client (mc) Commands:\n    - List configured aliases:    mc alias list\n    - List available buckets:     mc ls minio\n    - Copy files from bucket:     mc cp minio/<bucket>/prefix <destination>\n    - Upload files to bucket:     mc cp <source> minio/<bucket>/prefix\n    - Remove files from bucket:   mc rm minio/<bucket>/prefix\n    - Create a new bucket:        mc mb minio/<bucket>\n    - Get help:                   mc --help\n\nrclone Commands:\n    - List configured remotes:    rclone listremotes\n    - List available buckets:     rclone lsd minio:\n    - List files in bucket:       rclone ls minio:<bucket>\n    - Copy files from bucket:     rclone copy minio:<bucket>/prefix <destination>\n    - Upload files to bucket:     rclone copy <source> minio:<bucket>/prefix\n    - Remove files from bucket:   rclone delete minio:<bucket>/prefix\n    - Create a new bucket:        rclone mkdir minio:<bucket>\n    - Get help:                   rclone help\n\nAWS CLI Commands:\n    - List configured profiles:   aws configure list-profiles\n    - List available buckets:     aws s3 ls\n    - Copy files from bucket:     aws s3 cp s3://<bucket>/prefix <destination>\n    - Upload files to bucket:     aws s3 cp <source> s3://<bucket>/prefix\n    - Remove files from bucket:   aws s3 rm s3://<bucket>/prefix\n    - Create a new bucket:        aws s3 mb s3://<bucket>\n    - Get help:                   aws s3 help\n\nboto3 Python Examples:\n    import boto3\n    s3 = boto3.Session(profile_name="default").client('s3')  # Create S3 client with MinIO endpoint\n    buckets = s3.list_buckets()  # List buckets\n    objects = s3.list_objects_v2(Bucket='default-bucket')  # List objects in bucket named "default-bucket"\n\n--------------------------------------------\nEOF\n	0538bf15-b13b-4c5b-988a-2d44a596e2ed	2026-03-17 12:30:30.743523+00	2026-03-17 12:30:30.743523+00	system	system
