76c9491a-99e5-47d3-923c-312106b04db5	mount/install_kubectl.sh	#!/bin/bash\n\n# Download the binary\ncurl -L "https://dl.k8s.io/release/$(curl -L -s https://dl.k8s.io/release/stable.txt)/bin/linux/amd64/kubectl" \\\n    --create-dirs \\\n    -o /usr/local/bin/kubectl\n\n# Make the binary executable\nchmod +x /usr/local/bin/kubectl\n	0538bf15-b13b-4c5b-988a-2d44a596e2ed	2026-03-17 12:30:30.743536+00	2026-03-17 12:30:30.743536+00	system	system
19193869-3f1c-47d2-9f47-51493b31729a	templates/_helpers.tpl	# Base URL helper\n{{- define "httpRoute.baseUrl" -}}\n{{- $projectId := default "project_id" .Values.metadata.project_id -}}\n{{- $userId := default "user_id" .Values.metadata.user_id -}}\n{{- $workloadId := default (include "release.fullname" .) .Values.metadata.workload_id -}}\n{{- printf "/%s/%s/%s" $projectId $userId $workloadId }}\n{{- end -}}\n\n# Release name helper\n{{- define "release.name" -}}\n{{- default .Chart.Name .Values.nameOverride | trunc 63 | trimSuffix "-" -}}\n{{- end -}}\n\n# Release fullname helper\n{{- define "release.fullname" -}}\n{{- $currentTime := now | date "20060102-1504" -}}\n{{- if .Values.fullnameOverride -}}\n{{- .Values.fullnameOverride | trunc 63 | trimSuffix "-" -}}\n{{- else -}}\n{{- if ne .Release.Name "release-name" -}}\n{{- include "release.name" . }}-{{ .Release.Name | trunc 63 | trimSuffix "-" -}}\n{{- else -}}\n{{- include "release.name" . }}-{{ $currentTime | lower | trunc 63 | trimSuffix "-" -}}\n{{- end -}}\n{{- end -}}\n{{- end -}}\n\n# Container resources helper\n{{- define "container.resources" -}}\nrequests:\n  memory: "{{ max (mul .Values.gpus .Values.memory_per_gpu) 4 }}Gi"\n  cpu: "{{ max (mul .Values.gpus .Values.cpu_per_gpu) 1 }}"\n  {{- if .Values.gpus }}\n  amd.com/gpu: "{{ .Values.gpus }}"\n  {{- end }}\nlimits:\n  memory: "{{ max (mul .Values.gpus .Values.memory_per_gpu) 4 }}Gi"\n  cpu: "{{ max (mul .Values.gpus .Values.cpu_per_gpu) 1 }}"\n  {{- if .Values.gpus }}\n  amd.com/gpu: "{{ .Values.gpus }}"\n  {{- end }}\n{{- end -}}\n\n# Container environment variables helper\n{{- define "container.env" -}}\n{{- range $key, $value := .Values.env_vars }}\n{{- if (typeIs "string" $value) }}\n- name: {{ $key }}\n  value: {{ tpl $value $ | quote }}\n{{- else }}\n- name: {{ $key }}\n  valueFrom:\n    secretKeyRef:\n      name: {{ $value.name }}\n      key: {{ $value.key }}\n{{- end }}\n{{- end }}\n- name: BASE_URL\n  value: {{ include "httpRoute.baseUrl" . | quote }}\n{{- end -}}\n\n# Container volume mounts helper\n{{- define "container.volumeMounts" -}}\n- mountPath: /workload\n  name: ephemeral-storage\n- mountPath: /workload/mount\n  name: workload-mount\n- mountPath: /dev/shm\n  name: dshm\n{{- if .Values.persistent_storage.enabled }}\n{{- range $key, $value := .Values.persistent_storage.volumes }}\n- mountPath: {{ tpl $value.mount_path $ }}\n  name: {{ $key }}\n{{- end }}\n{{- end }}\n{{- end -}}\n\n# Container volumes helper\n{{- define "container.volumes" -}}\n{{- if .Values.storage.ephemeral.storageClassName -}}\n- ephemeral:\n    volumeClaimTemplate:\n      spec:\n        {{- if .Values.storage.ephemeral.accessModes }}\n        accessModes: {{ .Values.storage.ephemeral.accessModes }}\n        {{- else }}\n        accessModes:\n          - ReadWriteOnce\n        {{- end }}\n        resources:\n          requests:\n            storage: {{ .Values.storage.ephemeral.quantity }}\n        storageClassName: {{ .Values.storage.ephemeral.storageClassName }}\n  name: ephemeral-storage\n{{- else }}\n- emptyDir: {}\n  name: ephemeral-storage\n  sizeLimit: {{ .Values.storage.ephemeral.quantity }}\n{{- end }}\n- emptyDir:\n    medium: Memory\n    sizeLimit: {{ .Values.storage.dshm.sizeLimit }}\n  name: dshm\n- configMap:\n    name: {{ include "release.fullname" . }}\n  name: workload-mount\n{{- if .Values.persistent_storage.enabled }}\n{{- range $key, $value := .Values.persistent_storage.volumes }}\n- persistentVolumeClaim:\n    claimName: {{ tpl $value.pvc_name $ }}\n  name: {{ $key }}\n{{- end }}\n{{- end }}\n{{- end -}}\n	0538bf15-b13b-4c5b-988a-2d44a596e2ed	2026-03-17 12:30:30.743539+00	2026-03-17 12:30:30.743539+00	system	system
bb88b637-9ab9-472b-b71d-200c445532bf	templates/ingress.yaml	{{- if .Values.ingress.enabled -}}\napiVersion: networking.k8s.io/v1\nkind: Ingress\nmetadata:\n  name: {{ include "release.fullname" . }}\n  annotations:\n    nginx.ingress.kubernetes.io/enable-websocket: "true"\n    nginx.ingress.kubernetes.io/proxy-connect-timeout: "3600"\n    nginx.ingress.kubernetes.io/proxy-http-version: "1.1"\n    nginx.ingress.kubernetes.io/proxy-read-timeout: "3600"\n    nginx.ingress.kubernetes.io/proxy-send-timeout: "3600"\n    nginx.ingress.kubernetes.io/proxy-set-header-Origin: ""\n    nginx.ingress.kubernetes.io/rewrite-target: /$2\n    nginx.ingress.kubernetes.io/use-regex: "true"\nspec:\n  rules:\n  - http:\n      paths:\n      - backend:\n          service:\n            name: {{ include "release.fullname" . }}\n            port:\n              number: 80\n        path: {{ include "httpRoute.baseUrl" . }}(/|$)(.*)\n        pathType: ImplementationSpecific\n{{- end -}}\n	0538bf15-b13b-4c5b-988a-2d44a596e2ed	2026-03-17 12:30:30.743541+00	2026-03-17 12:30:30.743542+00	system	system
8f4908cd-d373-452e-8307-55b1c4e9dbd8	templates/deployment.yaml	{{- define "deployment" -}}\napiVersion: apps/v1\nkind: Deployment\nmetadata:\n  name: {{ include "release.fullname" . }}\n  labels:\n    app: {{ include "release.fullname" . }}\n    {{- range $key, $value := .Values.metadata.labels }}\n    {{ $key }}: {{ $value | quote }}\n    {{- end }}\nspec:\n  replicas: 1\n  selector:\n    matchLabels:\n      app: {{ include "release.fullname" . }}\n  template:\n    metadata:\n      annotations:\n        {{- range $key, $value := .Values.metadata.annotations }}\n        {{ $key }}: {{ tpl $value $ | quote }}\n        {{- end }}\n        {{- if .Values.persistent_storage.enabled }}\n        {{- range $key, $value := .Values.pvc_annotations }}\n        {{ $key }}: {{ tpl $value $ | quote }}\n        {{- end }}\n        {{- end }}\n      labels:\n        app: {{ include "release.fullname" . }}\n    spec:\n      {{- if .Values.imagePullSecrets }}\n      imagePullSecrets:\n        {{- range .Values.imagePullSecrets }}\n        - name: {{ . }}\n        {{- end }}\n      {{- end }}\n      containers:\n      - name: {{ .Chart.Name }}\n        {{- if .Values.entrypoint }}\n        args:\n        - |\n          {{- .Values.entrypoint | nindent 12 }}\n        command: ["sh", "-c"]\n        {{- end }}\n        {{- if .Values.env_vars }}\n        env:\n          {{- include "container.env" . | nindent 12 }}\n        {{- end }}\n        image: {{ .Values.image | quote}}\n        imagePullPolicy: {{ default "Always" .Values.imagePullPolicy | quote }}\n        {{- if .Values.livenessProbe }}\n        livenessProbe:\n          {{- .Values.livenessProbe | toYaml | nindent 12 -}}\n        {{- end }}\n        ports:\n          {{- range $key, $value := .Values.deployment.ports }}\n          - name: {{ $key }}\n            containerPort: {{ $value }}\n          {{- end }}\n        {{- if .Values.readinessProbe }}\n        readinessProbe:\n          {{- .Values.readinessProbe | toYaml | nindent 12 -}}\n        {{- end }}\n        resources:\n          {{- include "container.resources" . | nindent 12 }}\n        {{- if .Values.startupProbe }}\n        startupProbe:\n          {{- .Values.startupProbe | toYaml | nindent 12 -}}\n        {{- end }}\n        volumeMounts:\n          {{- include "container.volumeMounts" . | nindent 12 }}\n      volumes:\n        {{- include "container.volumes" . | nindent 8 }}\n{{- end -}}\n\n{{- define "deployment_stripped" -}}\n{{- $deployment := include "deployment" . | fromYaml }}\n{{- $ := unset $deployment "metadata" }}\n{{- $ := unset $deployment.spec.template "metadata" }}\n{{- $deployment | toYaml }}\n{{- end -}}\n\n{{- define "deployment_wrapped_with_kaiwoservice" -}}\napiVersion: kaiwo.silogen.ai/v1alpha1\nkind: KaiwoService\nmetadata:\n  name: {{ include "release.fullname" . }}\n  labels:\n    app: {{ include "release.fullname" . }}\n    {{- range $key, $value := .Values.metadata.labels }}\n    {{ $key }}: {{ $value | quote }}\n    {{- end }}\nspec:\n  deployment:\n    {{- include "deployment" . | nindent 4 }}\n{{- end -}}\n\n{{- if .Values.kaiwo.enabled -}}\n{{- include "deployment_wrapped_with_kaiwoservice" . }}\n{{- else -}}\n{{- include "deployment" . }}\n{{- end -}}\n	0538bf15-b13b-4c5b-988a-2d44a596e2ed	2026-03-17 12:30:30.743544+00	2026-03-17 12:30:30.743544+00	system	system
0652ca16-910e-470c-9450-ae7fdc3044e6	templates/service.yaml	apiVersion: v1\nkind: Service\nmetadata:\n  name: {{ include "release.fullname" . }}\n  labels:\n    app: {{ include "release.fullname" . }}\nspec:\n  type: ClusterIP\n  ports:\n    {{ range $name, $port := .Values.deployment.ports }}\n    {{- if ne $name "http" }}\n    - name: {{ $name }}\n      port: {{ $port }}\n      targetPort: {{ $port }}\n    {{- else -}}\n    - name: {{ $name }}\n      port: 80\n      targetPort: {{ $port }}\n    {{- end }}\n    {{- end }}\n  selector:\n    app: {{ include "release.fullname" . }}\n	0538bf15-b13b-4c5b-988a-2d44a596e2ed	2026-03-17 12:30:30.743547+00	2026-03-17 12:30:30.743547+00	system	system
46f60410-9c4f-42d8-b016-12a7aefdb6b4	templates/httproute.yaml	{{- if .Values.http_route.enabled -}}\napiVersion: gateway.networking.k8s.io/v1\nkind: HTTPRoute\nmetadata:\n  name: {{ include "release.fullname" . }}\nspec:\n  parentRefs:\n    - name: https\n      namespace: kgateway-system\n  rules:\n    - backendRefs:\n        - name:  {{ include "release.fullname" . }}\n          port: 80\n      matches:\n      - path:\n          type: PathPrefix\n          value: {{ include "httpRoute.baseUrl" . }}\n      filters:\n        - type: URLRewrite\n          urlRewrite:\n            path:\n              type: ReplacePrefixMatch\n              replacePrefixMatch: /\n{{- end -}}\n	0538bf15-b13b-4c5b-988a-2d44a596e2ed	2026-03-17 12:30:30.74355+00	2026-03-17 12:30:30.74355+00	system	system
bbbf3067-77e9-4fab-93ea-8a3dc814ee2d	templates/configmap.yaml	apiVersion: v1\nkind: ConfigMap\nmetadata:\n  name: {{ include "release.fullname" . }}\ndata:\n{{- $files := .Files }}\n{{- range $path, $_ := .Files.Glob "mount/*" }}\n  {{ $key := $path | trimPrefix "mount/" }}\n  {{- $key }}: |\n{{ $files.Get $path | indent 4 }}\n{{- end }}\n	0538bf15-b13b-4c5b-988a-2d44a596e2ed	2026-03-17 12:30:30.743553+00	2026-03-17 12:30:30.743553+00	system	system
fd64e7cb-24a1-40f9-a3d8-242562f603e6	values.schema.json	{\n  "$schema": "http://json-schema.org/draft-07/schema#",\n  "title": "Values",\n  "type": "object",\n  "properties": {\n    "image": {\n      "type": "string",\n      "description": "Docker image to use"\n    },\n    "labels": {\n      "type": "object",\n      "description": "Labels to be added to the Kubernetes manifest",\n      "additionalProperties": true\n    },\n    "imagePullSecrets": {\n      "type": "array",\n      "description": "Image pull secrets",\n      "items": {\n        "type": "string"\n      }\n    },\n    "bucketStorageHost": {\n      "type": "string",\n      "description": "Bucket storage host URL"\n    },\n    "bucketSecret": {\n      "type": "object",\n      "description": "Bucket storage credential secret values, required to have the secret already setup in the cluster (e.g. via external secrets)",\n      "properties": {\n        "name": {\n          "type": "string",\n          "description": "The name of the secret in the cluster that contains the bucket storage credentials",\n          "default": "minio-credentials"\n        },\n        "accessKeyKey": {\n          "type": "string",\n          "description": "The key in the secret that contains the access key",\n          "default": "minio-access-key"\n        },\n        "secretKeyKey": {\n          "type": "string",\n          "description": "The key in the secret that contains the bucket storage secret key",\n          "default": "minio-secret-key"\n        }\n      },\n      "required": ["name", "accessKeyKey", "secretKeyKey"]\n    },\n    "hfTokenSecret": {\n      "type": ["object", "null"],\n      "description": "Optional secret reference that contains a HuggingFace token",\n      "properties": {\n        "name": {\n          "type": "string",\n          "description": "The name of the secret in the cluster that contains the HuggingFace token"\n        },\n        "key": {\n          "type": "string",\n          "description": "The key in the secret that contains the HuggingFace token"\n        }\n      }\n    },\n    "modelId": {\n      "type": "string",\n      "description": "Huggingface model id, which is in the format of organization/model-name"\n    },\n    "bucketPath": {\n      "type": "string",\n      "description": "Path in the bucket storage where this model should be stored"\n    },\n    "modelRevision": {\n      "type": ["string", "null"],\n      "description": "Optional string that specifies which revision of the model should be downloaded"\n    },\n    "downloadExcludeGlob": {\n      "type": "string",\n      "description": "Optional string that specifies which files in the huggingface model repository should be excluded from the download",\n      "default": "original/*"\n    },\n    "allowOverwrite": {\n      "type": "boolean",\n      "description": "Optionally set to true to allow overwriting existing files in the bucket",\n      "default": false\n    },\n    "storageQuantity": {\n      "type": "string",\n      "description": "How much space needs to be allocated",\n      "default": "64Gi"\n    },\n    "storageClass": {\n      "type": ["string", "null"],\n      "description": "Optionally set this to use a specific storageClass for the storage"\n    },\n      "kaiwo": {\n        "type": "object",\n        "properties": {\n          "enabled": {\n            "type": "boolean",\n            "description": "If true, use Kaiwo CRDs to have Kaiwo operator manage the workload"\n          }\n        }\n      }\n  },\n  "required": ["image", "bucketStorageHost", "bucketCredentialsSecret", "modelId", "bucketPath"]\n}\n	67871e8d-6294-4e44-9eab-f3da06d3c50e	2026-03-17 12:30:30.756322+00	2026-03-17 12:30:30.756324+00	system	system
85f7deb0-31dd-41c0-915a-7f90d0b852a2	Chart.yaml	apiVersion: v2\nname: download-huggingface-model-to-bucket\ndescription: A Helm chart for downloading HuggingFace resources to a bucket\nversion: 0.0.1\n	67871e8d-6294-4e44-9eab-f3da06d3c50e	2026-03-17 12:30:30.756328+00	2026-03-17 12:30:30.756328+00	system	system
46aeee2b-e3f0-471e-b86a-e74fef178501	values.yaml	### General chart values ###\nimage: ghcr.io/silogen/logistics:v0.1\n\n# kaiwo settings (if enabled, use kaiwo CRDs to have kaiwo operator manage the workload)\nkaiwo:\n  enabled: false\n\n# Use to add labels to the metadata of the resources created by this workload.\nlabels: {}\n\n# Extra annotations such as an imagePullSecrets\nimagePullSecrets: []\n  # Example:\n  # imagePullSecrets:\n  #   - "regcred"\n\n# Configure these to match the credentials in your cluster:\nbucketStorageHost: http://minio.minio-tenant-default.svc.cluster.local:80\nbucketCredentialsSecret:\n  name: minio-credentials\n  accessKeyKey: minio-access-key\n  secretKeyKey: minio-secret-key\nhfTokenSecret: {} # Optional secret reference that contains the Huggingface token\n# Example:\n# hfTokenSecret:\n#   name: hf-token\n#   key: hf-token\n\n# Inputs:\nmodelId: "yujiepan/llama-3.1-tiny-random" # Huggingface model id, which is in the format of organization/model-name\nbucketPath: default-bucket/models/yujiepan/llama-3.1-tiny-random # Path in the bucket storage where this model should be stored. In the format bucket-name/path/separated/by/slashes/name-for-resulting-directory\nmodelRevision: # Optional string that specifies which revision of the model should be downloaded.\ndownloadExcludeGlob: "original/*" # Optional string that specifies which files in the huggingface model repository should be excluded from the download\nallowOverwrite: false # Optionally set to true to allow overiwriting existing files in the bucket\nstorageQuantity: 64Gi  # How much space needs to be allocated to store the model in the container (before pushing to bucket storage).\nstorageClass: mlstorage # Set this to use a specific storageClass for the storage. If not specified, will simply use an ephemeral_storage request.\n	67871e8d-6294-4e44-9eab-f3da06d3c50e	2026-03-17 12:30:30.756331+00	2026-03-17 12:30:30.756332+00	system	system
29d1d30f-ce1b-4df6-94a9-35d351b512f9	templates/httproute.yaml	{{- if .Values.http_route.enabled -}}\napiVersion: gateway.networking.k8s.io/v1\nkind: HTTPRoute\nmetadata:\n  name: {{ include "release.fullname" . }}\nspec:\n  parentRefs:\n    - name: https\n      namespace: kgateway-system\n  rules:\n    - backendRefs:\n        - name:  {{ include "release.fullname" . }}\n          port: 80\n      matches:\n      - path:\n          type: PathPrefix\n          value: {{ include "httpRoute.baseUrl" . }}\n      filters:\n        - type: URLRewrite\n          urlRewrite:\n            path:\n              type: ReplacePrefixMatch\n              replacePrefixMatch: /\n{{- end -}}\n	cfbe1c00-8b21-45d5-bce1-6a1926addb7d	2026-03-17 12:30:30.99312+00	2026-03-17 12:30:30.99312+00	system	system
47226686-367a-4ec8-acda-5478419841b2	templates/job.yaml	{{- define "job" -}}\napiVersion: batch/v1\nkind: Job\nmetadata:\n  name: "{{ .Release.Name }}-job"\n  {{- if .Values.labels }}\n  labels:\n    {{- range $label, $value := .Values.labels }}\n    {{ $label }}: {{ $value | quote }}\n    {{- end }}\n  {{- end }}\nspec:\n  ttlSecondsAfterFinished: 3600\n  backoffLimit: 0\n  template:\n    spec:\n      restartPolicy: Never\n      {{- if .Values.imagePullSecrets }}\n      imagePullSecrets:\n        {{- range .Values.imagePullSecrets }}\n        - name: {{ . }}\n        {{- end }}\n      {{- end }}\n      containers:\n      - name: hf-to-bucket\n        image: {{ .Values.image }}\n        imagePullPolicy: Always\n        workingDir: /app\n        command:\n        - sh\n        - -e\n        - -u\n        - -c\n        args:\n        - |\n          ###################################\n          echo 'Setting up local directories'\n          mkdir -p local_models\n          ###################################\n          echo 'Setting up minio'\n          mc alias set minio-host ${BUCKET_STORAGE_HOST} ${BUCKET_STORAGE_ACCESS_KEY} ${BUCKET_STORAGE_SECRET_KEY}\n          ###################################\n          echo 'Downloading the model to the local container'\n          huggingface-cli download {{ .Values.modelId }} \\\n            --exclude '{{ .Values.downloadExcludeGlob }}' \\\n            {{- if .Values.modelRevision }}\n            --revision {{ .Values.modelRevision }}\n            {{- end }}\n            --local-dir local_models/downloaded_model\n          ###################################\n          echo 'Uploading the model to the bucket, to {{ .Values.bucketPath | trimSuffix "/" | replace  "'" "'\\\\''" }}'\n          {{- $remotePath := printf "minio-host/'%s'/" (.Values.bucketPath | trimSuffix "/" | replace  "'" "'\\\\''") }}\n          mc mirror --exclude '.cache/huggingface/*' \\\n            --exclude '.gitattributes' \\\n            {{- if .Values.allowOverwrite }}\n            --overwrite \\\n            {{- end }}\n            local_models/downloaded_model/ {{ $remotePath }}\n        env:\n          {{- if .Values.hfTokenSecret }}\n          - name: HF_TOKEN\n            valueFrom:\n              secretKeyRef:\n                name: {{ .Values.hfTokenSecret.name }}\n                key: {{ .Values.hfTokenSecret.key }}\n          {{- end }}\n          - name: BUCKET_STORAGE_HOST\n            value: {{ .Values.bucketStorageHost }}\n          - name: BUCKET_STORAGE_ACCESS_KEY\n            valueFrom:\n              secretKeyRef:\n                name: {{ .Values.bucketCredentialsSecret.name }}\n                key: {{ .Values.bucketCredentialsSecret.accessKeyKey }}\n          - name: BUCKET_STORAGE_SECRET_KEY\n            valueFrom:\n              secretKeyRef:\n                name: {{ .Values.bucketCredentialsSecret.name }}\n                key: {{ .Values.bucketCredentialsSecret.secretKeyKey }}\n        resources:\n          requests:\n            memory: 1Gi\n            cpu: 1\n          limits:\n            memory: 1Gi\n            cpu: 1\n        {{- if .Values.storageClass }}\n        volumeMounts:\n          - mountPath: /app\n            name: {{ .Release.Name }}-volume\n        {{- end }}\n        securityContext:\n          allowPrivilegeEscalation: false\n          runAsNonRoot: true\n          runAsUser: 1000\n          runAsGroup: 1000\n          seccompProfile:\n            type: RuntimeDefault\n          capabilities:\n            drop: ["ALL"]\n      securityContext:\n        fsGroup: 1000\n      volumes:\n        - name: {{ .Release.Name }}-volume\n        {{- if .Values.storageClass }}\n          ephemeral:\n            volumeClaimTemplate:\n              spec:\n                accessModes: [ "ReadWriteOnce" ]\n                storageClassName: {{ .Values.storageClass }}\n                resources:\n                  requests:\n                    storage: "{{ .Values.storageQuantity }}"\n        {{- else }}\n          emptyDir:\n            sizeLimit: "{{ .Values.storageQuantity }}"\n        {{- end }}\n{{- end -}}\n\n{{- define "job_wrapped_with_kaiwojob" -}}\napiVersion: kaiwo.silogen.ai/v1alpha1\nkind: KaiwoJob\nmetadata:\n  name: "{{ .Release.Name }}-job"\nspec:\n  job:\n    {{- include "job" . | nindent 4 }}\n{{- end -}}\n\n{{- if .Values.kaiwo.enabled -}}\n{{- include "job_wrapped_with_kaiwojob" . }}\n{{- else -}}\n{{- include "job" . }}\n{{- end -}}\n	67871e8d-6294-4e44-9eab-f3da06d3c50e	2026-03-17 12:30:30.756334+00	2026-03-17 12:30:30.756335+00	system	system
bde4ecf2-130b-478e-8733-984bcb82d5ca	values.schema.json	{\n    "$schema": "http://json-schema.org/draft-07/schema#",\n    "type": "object",\n    "properties": {\n      "finetuningImage": {\n        "type": "string",\n        "description": "Finetuning engine image"\n      },\n      "labels": {\n        "type": "object",\n        "description": "Any labels to add for the manifest, recommended: kueue",\n        "additionalProperties": true\n      },\n      "imagePullSecrets": {\n        "type": "array",\n        "description": "Any imagePullSecrets to use",\n        "items": {\n          "type": "string"\n        }\n      },\n      "bucketStorageHost": {\n        "type": "string",\n        "description": "The cloud storage host URL"\n      },\n      "bucketCredentialsSecret": {\n        "type": "object",\n        "description": "Bucket storage credential secret values, required to have the secret already setup in the cluster (e.g. via external secrets)",\n        "properties": {\n          "name": {\n            "type": "string",\n            "description": "The name of the secret in the cluster that contains the bucket storage credentials",\n            "default": "minio-credentials"\n          },\n          "accessKeyKey": {\n            "type": "string",\n            "description": "The key in the secret that contains the access key",\n            "default": "minio-access-key"\n          },\n          "secretKeyKey": {\n            "type": "string",\n            "description": "The key in the secret that contains the access key",\n            "default": "minio-secret-key"\n          }\n        }\n      },\n      "downloadsReservedSize": {\n        "type": "string",\n        "description": "How much space to reserve for model and data downloads",\n        "default": "64Gi"\n      },\n      "checkpointsReservedSize": {\n        "type": "string",\n        "description": "How much space to reserve for model and data downloads",\n        "default": "512Gi"\n      },\n      "storageClass": {\n        "type": ["string", "null"],\n        "description": "Optionally set this to use a specific storageClass for the storage"\n      },\n      "finetuningGpus": {\n        "type": "integer",\n        "description": "How many GPUs to use",\n        "default": 1\n      },\n      "distributedType": {\n        "type": "string",\n        "default": "auto-deepspeed-stage1",\n        "enum": ["auto-deepspeed-stage1", "auto-deepspeed-stage3", "auto-ddp", "auto-single-process", "custom-accelerate-config"],\n        "description": "The type of distributed training to use. If using custom-accelerate-config, provide the config as an object in customAccelerateConfig"\n      },\n      "customAccelerateConfig": {\n        "type": ["object", "null"]\n      },\n      "mergeAdapter": {\n        "type": "boolean",\n        "description": "Whether to merge the adapter at the end of training or not.",\n        "default": false\n      },\n      "checkpointsRemote": {\n        "type": "string",\n        "description": "Path in bucket storage where to store the checkpoints."\n      },\n      "basemodel": {\n        "type": "string",\n        "description": "Path in bucket storage where the basemodel is stored, or prefixed by hf:// for a model from the HuggingFace Hub."\n      },\n      "model": {\n        "type": "string",\n        "description": "Path in bucket storage where the basemodel is stored.",\n        "default": ""\n      },\n      "hfDownloadExcludeGlob": {\n        "type": "string",\n        "description": "Glob pattern to exclude files when downloading from Hugging Face Hub. Used to avoid downloading unnecessary large files like duplicate weight files.",\n        "default": ""\n      },\n      "hfTokenSecret": {\n        "type": ["object", "null"],\n        "description": "Optional secret that contains the Hugging Face token for downloading models from the Hugging Face Hub."\n      },\n      "finetuning_config": {\n        "discriminator": {\n          "mapping": {\n            "dpo": "#/$defs/DPOExperimentConfig",\n            "sft": "#/$defs/SFTExperimentConfig"\n          },\n          "propertyName": "method"\n        },\n        "oneOf": [\n          {\n            "$ref": "#/$defs/SFTExperimentConfig"\n          },\n          {\n            "$ref": "#/$defs/DPOExperimentConfig"\n          }\n        ],\n        "title": "Finetuning Config"\n      },\n      "kaiwo": {\n        "type": "object",\n        "properties": {\n          "enabled": {\n            "type": "boolean",\n            "description": "If true, use Kaiwo CRDs to have Kaiwo operator manage the workload"\n          }\n        }\n      }\n    },\n    "required": ["bucketCredentialsSecret", "checkpointsRemote", "basemodel", "finetuning_config", "kaiwo"],\n    "$defs": {\n      "AutoSplitDataInput": {\n        "additionalProperties": false,\n        "description": "Automatic validation split from the training data",\n        "properties": {\n          "type": {\n            "const": "AUTO_SPLIT",\n            "title": "Type",\n            "type": "string"\n          },\n          "data_type": {\n            "default": "ChatConversation",\n            "description": "Generally, the data_type is automatically set based on the experiment config method.",\n            "title": "Data Type",\n            "type": "string"\n          },\n          "ratio": {\n            "default": 0.2,\n            "description": "Ratio of the training data to use for validation",\n            "title": "Ratio",\n            "type": "number"\n          },\n          "seed": {\n            "default": 1289525893,\n            "description": "Seed for the random number generator for splitting",\n            "title": "Seed",\n            "type": "integer"\n          }\n        },\n        "required": [\n          "type"\n        ],\n        "title": "AutoSplitDataInput",\n        "type": "object"\n      },\n      "BatchsizeConfig": {\n        "additionalProperties": false,\n        "description": "Config for determining the total batch size\\n\\nTotal batch size is the effective batch size for the complete training run. It is equal to\\nnumber of processes * per-device batch size * accumulation.\\n\\nThe maximum batch size per device is the maximum batch size that can be accommodated on a single device.\\nThis mostly limited by the memory capacity of the device.",\n        "properties": {\n          "total_train_batch_size": {\n            "description": "The total batch size for the training run",\n            "title": "Total Train Batch Size",\n            "anyOf": [\n              {\n                "type": "integer"\n              },\n              {\n                "type": "null"\n              }\n            ]\n          },\n          "max_per_device_train_batch_size": {\n            "description": "The maximum training batch size per device",\n            "title": "Max Per Device Train Batch Size",\n            "type": "integer"\n          },\n          "per_device_eval_batch_size": {\n            "anyOf": [\n              {\n                "type": "integer"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "description": "The maximum eval batch size per device, if not given, will use same as training batch size",\n            "title": "Per Device Eval Batch Size"\n          }\n        },\n        "required": [\n          "total_train_batch_size",\n          "max_per_device_train_batch_size"\n        ],\n        "title": "BatchsizeConfig",\n        "type": "object"\n      },\n      "BnBQuantizationConfig": {\n        "additionalProperties": false,\n        "description": "Bits and Bytes configuration\\n\\nThe options are from the BitsAndBytes config,\\nsee: https://huggingface.co/docs/transformers/en/main_classes/quantization#transformers.BitsAndBytesConfig",\n        "properties": {\n          "quantization_type": {\n            "const": "bits-and-bytes",\n            "default": "bits-and-bytes",\n            "title": "Quantization Type",\n            "type": "string"\n          },\n          "load_in_8bit": {\n            "default": false,\n            "title": "Load In 8Bit",\n            "type": "boolean"\n          },\n          "load_in_4bit": {\n            "default": false,\n            "title": "Load In 4Bit",\n            "type": "boolean"\n          },\n          "llm_int8_threshold": {\n            "default": 6.0,\n            "title": "Llm Int8 Threshold",\n            "type": "number"\n          },\n          "llm_int8_skip_modules": {\n            "anyOf": [\n              {\n                "items": {\n                  "type": "string"\n                },\n                "type": "array"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "title": "Llm Int8 Skip Modules"\n          },\n          "llm_int8_enable_fp32_cpu_offload": {\n            "default": false,\n            "title": "Llm Int8 Enable Fp32 Cpu Offload",\n            "type": "boolean"\n          },\n          "llm_int8_has_fp16_weight": {\n            "default": false,\n            "title": "Llm Int8 Has Fp16 Weight",\n            "type": "boolean"\n          },\n          "bnb_4bit_compute_dtype": {\n            "anyOf": [\n              {\n                "type": "string"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "title": "Bnb 4Bit Compute Dtype"\n          },\n          "bnb_4bit_quant_type": {\n            "anyOf": [\n              {\n                "const": "fp4",\n                "type": "string"\n              },\n              {\n                "const": "nf4",\n                "type": "string"\n              }\n            ],\n            "default": "fp4",\n            "title": "Bnb 4Bit Quant Type"\n          },\n          "bnb_4bit_use_double_quant": {\n            "default": false,\n            "title": "Bnb 4Bit Use Double Quant",\n            "type": "boolean"\n          },\n          "bnb_4bit_quant_storage": {\n            "anyOf": [\n              {\n                "type": "string"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "title": "Bnb 4Bit Quant Storage"\n          }\n        },\n        "title": "BnBQuantizationConfig",\n        "type": "object"\n      },\n      "ChatTemplateName": {\n        "description": "Chat template to use.",\n        "enum": [\n          "mistral-with-system",\n          "chat-ml",\n          "poro",\n          "keep-original",\n          "simplified-llama31"\n        ],\n        "title": "ChatTemplateName",\n        "type": "string"\n      },\n      "ChatTrainValidConfig": {\n        "additionalProperties": false,\n        "description": "Training time data configuration\\n\\nAlways defines some DataInput for training data and can include validation DataInput, though a trivial NoneDataInput\\nis also allowed for the validation side.\\n\\nAdditionally includes chat template and padding configurations, as those are part of the data input pipeline.",\n        "properties": {\n          "training_data": {\n            "anyOf": [\n              {\n                "$ref": "#/$defs/ConcatenationDataInput"\n              },\n              {\n                "$ref": "#/$defs/WeightedMixDataInput"\n              }\n            ],\n            "title": "Training Data"\n          },\n          "validation_data": {\n            "anyOf": [\n              {\n                "$ref": "#/$defs/ConcatenationDataInput"\n              },\n              {\n                "$ref": "#/$defs/AutoSplitDataInput"\n              },\n              {\n                "$ref": "#/$defs/NoneDataInput"\n              }\n            ],\n            "title": "Validation Data"\n          },\n          "chat_template_name": {\n            "$ref": "#/$defs/ChatTemplateName",\n            "default": "mistral-with-system"\n          },\n          "padding_side": {\n            "default": "right",\n            "description": "Padding side, right is usually right.",\n            "title": "Padding Side",\n            "type": "string"\n          },\n          "missing_pad_token_strategy": {\n            "$ref": "#/$defs/MissingPadTokenStrategy",\n            "default": "bos-repurpose",\n            "description": "See the MissingPadTokenStrategys for descriptions of the options"\n          }\n        },\n        "required": [\n          "training_data",\n          "validation_data"\n        ],\n        "title": "ChatTrainValidConfig",\n        "type": "object"\n      },\n      "ConcatenationDataInput": {\n        "additionalProperties": false,\n        "description": "A simple list of datasets\\n\\nThese are simply concatenated, the same as sampling all with equal weight.\\n\\nThe datasets themselves need to be in the finetuning supported JSONL formats.\\nFor SFT this means lines:\\n\\n    {\\"messages\\": {\\"content\\": \\"string\\", \\"role\\": \\"string\\"}}\\n\\nFor DPO this means lines of:\\n\\n    {\\"prompt_messages\\": {\\"content\\": \\"string\\", \\"role\\": \\"string\\"}, \\"chosen_messages\\": {\\"content\\": \\"string\\", \\"role\\": \\"string\\"}, \\"rejected_messages\\": {\\"content\\": \\"string\\", \\"role\\": \\"string\\"}}",\n        "properties": {\n          "type": {\n            "const": "CONCATENATION",\n            "title": "Type",\n            "type": "string"\n          },\n          "data_type": {\n            "default": "ChatConversation",\n            "description": "Generally, the data_type is automatically set based on the experiment config method.",\n            "title": "Data Type",\n            "type": "string"\n          },\n          "datasets": {\n            "items": {\n              "$ref": "#/$defs/DatasetDefinition"\n            },\n            "minItems": 1,\n            "title": "Datasets",\n            "type": "array"\n          }\n        },\n        "required": [\n          "type",\n          "datasets"\n        ],\n        "title": "ConcatenationDataInput",\n        "type": "object"\n      },\n      "DPOExperimentConfig": {\n        "additionalProperties": false,\n        "description": "A full DPO experiment's config\\n\\nSee the various sub-configs for their options.",\n        "properties": {\n          "method": {\n            "const": "dpo",\n            "default": "dpo",\n            "title": "Method",\n            "type": "string"\n          },\n          "data_conf": {\n            "$ref": "#/$defs/ChatTrainValidConfig",\n            "description": "The data input config"\n          },\n          "training_args": {\n            "$ref": "#/$defs/SilogenDPOConfig",\n            "description": "TRL DPOTrainerArguments with some restrictions"\n          },\n          "overrides": {\n            "$ref": "#/$defs/Overrides",\n            "default": {\n              "lr_multiplier": 1.0,\n              "lr_batch_size_scaling": "none"\n            },\n            "description": "Override options to simplify the config interface"\n          },\n          "batchsize_conf": {\n            "$ref": "#/$defs/BatchsizeConfig",\n            "description": "Batch size configuration"\n          },\n          "peft_conf": {\n            "anyOf": [\n              {\n                "$ref": "#/$defs/NoPeftConfig"\n              },\n              {\n                "$ref": "#/$defs/PretrainedPeftConfig"\n              },\n              {\n                "$ref": "#/$defs/GenericPeftConfig"\n              }\n            ],\n            "description": "Adapter configuration",\n            "title": "Peft Conf"\n          },\n          "run_conf": {\n            "$ref": "#/$defs/RunConfig",\n            "description": "Model related configuration"\n          },\n          "tracking": {\n            "anyOf": [\n              {\n                "$ref": "#/$defs/FinetuningTrackingConfig"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "description": "MLFlow tracking configuration"\n          },\n          "quant_conf": {\n            "anyOf": [\n              {\n                "$ref": "#/$defs/NoQuantizationConfig"\n              },\n              {\n                "$ref": "#/$defs/BnBQuantizationConfig"\n              }\n            ],\n            "default": {\n              "quantization_type": "no-quantization"\n            },\n            "description": "Quantization configuration",\n            "title": "Quant Conf"\n          }\n        },\n        "required": [\n          "data_conf",\n          "training_args",\n          "batchsize_conf",\n          "peft_conf",\n          "run_conf"\n        ],\n        "title": "DPOExperimentConfig",\n        "type": "object"\n      },\n      "DatasetDefinition": {\n        "additionalProperties": false,\n        "description": "Define how to load a dataset",\n        "properties": {\n          "path": {\n            "description": "Local path to a JSONL file in the finetuning data format",\n            "title": "Path",\n            "type": "string"\n          }\n        },\n        "required": [\n          "path"\n        ],\n        "title": "DatasetDefinition",\n        "type": "object"\n      },\n      "DebugOption": {\n        "enum": [\n          "underflow_overflow",\n          "tpu_metrics_debug"\n        ],\n        "title": "DebugOption",\n        "type": "string"\n      },\n      "FDivergenceType": {\n        "enum": [\n          "reverse_kl",\n          "js_divergence",\n          "alpha_divergence"\n        ],\n        "title": "FDivergenceType",\n        "type": "string"\n      },\n      "FSDPOption": {\n        "enum": [\n          "full_shard",\n          "shard_grad_op",\n          "no_shard",\n          "hybrid_shard",\n          "hybrid_shard_zero2",\n          "offload",\n          "auto_wrap"\n        ],\n        "title": "FSDPOption",\n        "type": "string"\n      },\n      "FinetuningTrackingConfig": {\n        "additionalProperties": false,\n        "description": "Settings that define how run details are logged",\n        "properties": {\n          "mlflow_server_uri": {\n            "description": "MLflow server URI. Can be local path.",\n            "title": "Mlflow Server Uri",\n            "type": "string"\n          },\n          "experiment_name": {\n            "description": "Experiment name that is used for MLFlow tracking.",\n            "title": "Experiment Name",\n            "type": "string"\n          },\n          "hf_mlflow_log_artifacts": {\n            "default": "False",\n            "description": "Whether to store model artifacts in MLFlow.",\n            "title": "Hf Mlflow Log Artifacts",\n            "type": "string"\n          }\n        },\n        "required": [\n          "mlflow_server_uri",\n          "experiment_name"\n        ],\n        "title": "FinetuningTrackingConfig",\n        "type": "object"\n      },\n      "GenericPeftConfig": {\n        "additionalProperties": false,\n        "description": "Config for any new initialized PEFT Adapter\\n\\nSee https://huggingface.co/docs/peft/tutorial/peft_model_config for the possible kwargs\\nand https://github.com/huggingface/peft/blob/v0.7.1/src/peft/utils/peft_types.py for the types.\\n\\nExample:\\n\\n    >>> loaded_data = {'peft_type':'LORA', 'task_type': 'CAUSAL_LM',\\n    ...         'peft_kwargs': {'r': 32, 'target_modules': ['v_proj']}}\\n    >>> generic_conf = GenericPeftConfig(**loaded_data)\\n    >>> generic_conf.get_peft_config()\\n    LoraConfig(task_type=<TaskType.CAUSAL_LM: 'CAUSAL_LM'>, peft_type=<PeftType.LORA: 'LORA'>, ...)",\n        "properties": {\n          "peft_type": {\n            "$ref": "#/$defs/PeftType"\n          },\n          "task_type": {\n            "$ref": "#/$defs/TaskType",\n            "default": "CAUSAL_LM"\n          },\n          "peft_kwargs": {\n            "additionalProperties": true,\n            "title": "Peft Kwargs",\n            "type": "object"\n          }\n        },\n        "required": [\n          "peft_type"\n        ],\n        "title": "GenericPeftConfig",\n        "type": "object"\n      },\n      "HubStrategy": {\n        "enum": [\n          "end",\n          "every_save",\n          "checkpoint",\n          "all_checkpoints"\n        ],\n        "title": "HubStrategy",\n        "type": "string"\n      },\n      "IntervalStrategy": {\n        "enum": [\n          "no",\n          "steps",\n          "epoch"\n        ],\n        "title": "IntervalStrategy",\n        "type": "string"\n      },\n      "MissingPadTokenStrategy": {\n        "description": "Specifies the available missing pad token strategies.\\n\\nWe've shown in a small set of experiments that repurposing EOS can start to hurt performance\\nwhile the other options seem to work equally well.\\n\\nRepurposing EOS is the default in many online sources, but it is actually a bad idea if we want to predict\\nEOS, as all the pad_token_ids get ignored in loss computation, and thus the model does not learn to predict\\nthe end of the text. However, for models that have additional tokens for end of message, end of turn, etc.\\nthis is not so dangerous.\\n\\nRepurposing BOS is similar to repurposing EOS, but since we do not need to predict BOS, this may be more sensible.\\n\\nRepurposing UNK can work with tokenizers that never produce UNKs in normal data (e.g. Mistral tokenizers should have\\na byte fall-back so that everything can be tokenized).\\n\\nUNK_CONVERT_TO_EOS uses a hack where the unk_token_id is initially used for padding, but in the collation phase the\\ninput-side UNKs (padding) gets set to EOS, so that the input-side padding looks like EOS. On the output-side, the\\nUNKs (padding) still gets ignored. NOTE: This will leave the tokenizer's pad_token_id set to the unk_token_id; so\\nany subsequent use of the model where padding is involved should somehow explicitly set the pad_token_id again.",\n        "enum": [\n          "eos-repurpose",\n          "bos-repurpose",\n          "unk-repurpose",\n          "unk-convert-to-eos"\n        ],\n        "title": "MissingPadTokenStrategy",\n        "type": "string"\n      },\n      "ModelArguments": {\n        "additionalProperties": false,\n        "description": "These are passed to AutoModelForCausalLM.from_pretrained\\n\\nSee parameter docstrings and help at:\\nhttps://huggingface.co/docs/transformers/main/en/main_classes/model#transformers.PreTrainedModel.from_pretrained\\nSee below in \\"Parameters for big model inference\\" too, it affects training too. Also note that this link takes you\\nto the transformers main branch version - be sure to compare with the installed version of transformers (that keeps\\nchanging over time, and it is difficult to keep this docstring up to date, so we wanted to link to the latest here).\\n\\nSome important parameters to consider are:\\n\\n- device_map :\\n    A map that specifies where each submodule should go. It doesn\\u2019t need to be refined to each parameter/buffer\\n    name, once a given module name is inside, every submodule of it will be sent to the same device. If we only pass\\n    the device (e.g., \\"cpu\\", \\"cuda:1\\", \\"mps\\", or a GPU ordinal rank like 1) on which the model will be allocated,\\n    the device map will map the entire model to this device. Passing device_map = 0 means put the whole model on GPU\\n    0.\\n- attn_implementation :\\n    The attention implementation to use in the model (if relevant). Can be any of \\"eager\\" (manual implementation of\\n    the attention), \\"sdpa\\" (using F.scaled_dot_product_attention), or \\"flash_attention_2\\" (using\\n    Dao-AILab/flash-attention). By default, if available, SDPA will be used for torch>=2.1.1. The default is\\n    otherwise the manual \\"eager\\" implementation.\\n\\nNOTE:\\n    This does not include quantization_config. Quantization config is specified separately.",\n        "properties": {\n          "torch_dtype": {\n            "default": "auto",\n            "title": "Torch Dtype",\n            "type": "string"\n          },\n          "device_map": {\n            "anyOf": [\n              {\n                "additionalProperties": {\n                  "anyOf": [\n                    {\n                      "type": "integer"\n                    },\n                    {\n                      "type": "string"\n                    }\n                  ]\n                },\n                "type": "object"\n              },\n              {\n                "type": "string"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "description": "Custom device map so that you can manually override the choices that HuggingFace would make. This can also be a string to specify \\"auto\\", \\"balanced_low_0\\", or \\"sequential\\".",\n            "title": "Device Map"\n          },\n          "max_memory": {\n            "anyOf": [\n              {\n                "additionalProperties": {\n                  "type": "string"\n                },\n                "type": "object"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "title": "Max Memory"\n          },\n          "low_cpu_mem_usage": {\n            "default": false,\n            "title": "Low Cpu Mem Usage",\n            "type": "boolean"\n          },\n          "attn_implementation": {\n            "anyOf": [\n              {\n                "type": "string"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "description": "Note: this can be set to \\"sdpa\\", \\"flash_attention_2\\", \\"eager\\".",\n            "title": "Attn Implementation"\n          },\n          "offload_folder": {\n            "anyOf": [\n              {\n                "type": "string"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "title": "Offload Folder"\n          },\n          "offload_state_dict": {\n            "anyOf": [\n              {\n                "type": "boolean"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "description": "Default is True if offloading (otherwise no effect)",\n            "title": "Offload State Dict"\n          },\n          "offload_buffers": {\n            "anyOf": [\n              {\n                "type": "boolean"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "title": "Offload Buffers"\n          },\n          "use_cache": {\n            "default": true,\n            "description": "Saves generated hidden states to speed up generation, see: https://discuss.huggingface.co/t/what-is-the-purpose-of-use-cache-in-decoder/958 This is mutually exclusive with gradient_checkpointing.",\n            "title": "Use Cache",\n            "type": "boolean"\n          },\n          "cache_dir": {\n            "anyOf": [\n              {\n                "type": "string"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "title": "Cache Dir"\n          },\n          "force_download": {\n            "default": false,\n            "title": "Force Download",\n            "type": "boolean"\n          },\n          "local_files_only": {\n            "default": false,\n            "title": "Local Files Only",\n            "type": "boolean"\n          },\n          "proxies": {\n            "anyOf": [\n              {\n                "additionalProperties": {\n                  "type": "string"\n                },\n                "type": "object"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "title": "Proxies"\n          },\n          "resume_download": {\n            "default": false,\n            "title": "Resume Download",\n            "type": "boolean"\n          },\n          "revision": {\n            "default": "main",\n            "title": "Revision",\n            "type": "string"\n          },\n          "code_revision": {\n            "default": "main",\n            "title": "Code Revision",\n            "type": "string"\n          },\n          "subfolder": {\n            "anyOf": [\n              {\n                "type": "string"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "title": "Subfolder"\n          },\n          "token": {\n            "anyOf": [\n              {\n                "type": "string"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "title": "Token"\n          },\n          "use_safetensors": {\n            "anyOf": [\n              {\n                "type": "boolean"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "title": "Use Safetensors"\n          },\n          "variant": {\n            "anyOf": [\n              {\n                "type": "string"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "title": "Variant"\n          },\n          "trust_remote_code": {\n            "default": false,\n            "description": "Warning: if set to True, allows execution of downloaded remote code.",\n            "title": "Trust Remote Code",\n            "type": "boolean"\n          }\n        },\n        "title": "ModelArguments",\n        "type": "object"\n      },\n      "NoPeftConfig": {\n        "additionalProperties": false,\n        "description": "A trivial config specifying that no peft is used",\n        "properties": {\n          "peft_type": {\n            "const": "NO_PEFT",\n            "title": "Peft Type",\n            "type": "string"\n          }\n        },\n        "required": [\n          "peft_type"\n        ],\n        "title": "NoPeftConfig",\n        "type": "object"\n      },\n      "NoQuantizationConfig": {\n        "additionalProperties": false,\n        "description": "A marker not to use quantization",\n        "properties": {\n          "quantization_type": {\n            "const": "no-quantization",\n            "default": "no-quantization",\n            "title": "Quantization Type",\n            "type": "string"\n          }\n        },\n        "title": "NoQuantizationConfig",\n        "type": "object"\n      },\n      "NoneDataInput": {\n        "additionalProperties": false,\n        "description": "A special type for not using data e.g. in validation",\n        "properties": {\n          "type": {\n            "const": "NONE",\n            "title": "Type",\n            "type": "string"\n          },\n          "data_type": {\n            "default": "ChatConversation",\n            "description": "Generally, the data_type is automatically set based on the experiment config method.",\n            "title": "Data Type",\n            "type": "string"\n          }\n        },\n        "required": [\n          "type"\n        ],\n        "title": "NoneDataInput",\n        "type": "object"\n      },\n      "OptimizerNames": {\n        "description": "Stores the acceptable string identifiers for optimizers.",\n        "enum": [\n          "adamw_torch",\n          "adamw_torch_fused",\n          "adamw_torch_xla",\n          "adamw_torch_npu_fused",\n          "adamw_apex_fused",\n          "adafactor",\n          "adamw_anyprecision",\n          "adamw_torch_4bit",\n          "adamw_torch_8bit",\n          "ademamix",\n          "sgd",\n          "adagrad",\n          "adamw_bnb_8bit",\n          "adamw_8bit",\n          "ademamix_8bit",\n          "lion_8bit",\n          "lion_32bit",\n          "paged_adamw_32bit",\n          "paged_adamw_8bit",\n          "paged_ademamix_32bit",\n          "paged_ademamix_8bit",\n          "paged_lion_32bit",\n          "paged_lion_8bit",\n          "rmsprop",\n          "rmsprop_bnb",\n          "rmsprop_bnb_8bit",\n          "rmsprop_bnb_32bit",\n          "galore_adamw",\n          "galore_adamw_8bit",\n          "galore_adafactor",\n          "galore_adamw_layerwise",\n          "galore_adamw_8bit_layerwise",\n          "galore_adafactor_layerwise",\n          "lomo",\n          "adalomo",\n          "grokadamw",\n          "schedule_free_radam",\n          "schedule_free_adamw",\n          "schedule_free_sgd",\n          "apollo_adamw",\n          "apollo_adamw_layerwise"\n        ],\n        "title": "OptimizerNames",\n        "type": "string"\n      },\n      "Overrides": {\n        "additionalProperties": false,\n        "description": "Override options\\n\\nThese implement dynamic scaling for the learning rate.",\n        "properties": {\n          "lr_multiplier": {\n            "default": 1.0,\n            "description": "Multiplier applied to the learning rate in the training_args",\n            "title": "Lr Multiplier",\n            "type": "number"\n          },\n          "lr_batch_size_scaling": {\n            "default": "none",\n            "description": "Scales the learning rate in the training_args by a factor derived from the total training batch size.             'none': No scaling.             'sqrt': Multiplies learning rate by square root of batch size (a classic scaling rule).             'linear': Multiplies learning rate by the batch size (a more modern scaling rule).\\n",\n            "enum": [\n              "none",\n              "sqrt",\n              "linear"\n            ],\n            "title": "Lr Batch Size Scaling",\n            "type": "string"\n          }\n        },\n        "title": "Overrides",\n        "type": "object"\n      },\n      "PeftType": {\n        "description": "Enum class for the different types of adapters in PEFT.\\n\\nSupported PEFT types:\\n- PROMPT_TUNING\\n- MULTITASK_PROMPT_TUNING\\n- P_TUNING\\n- PREFIX_TUNING\\n- LORA\\n- ADALORA\\n- BOFT\\n- ADAPTION_PROMPT\\n- IA3\\n- LOHA\\n- LOKR\\n- OFT\\n- XLORA\\n- POLY\\n- LN_TUNING\\n- VERA\\n- FOURIERFT\\n- HRA\\n- BONE\\n- RANDLORA\\n- C3A",\n        "enum": [\n          "PROMPT_TUNING",\n          "MULTITASK_PROMPT_TUNING",\n          "P_TUNING",\n          "PREFIX_TUNING",\n          "LORA",\n          "ADALORA",\n          "BOFT",\n          "ADAPTION_PROMPT",\n          "IA3",\n          "LOHA",\n          "LOKR",\n          "OFT",\n          "POLY",\n          "LN_TUNING",\n          "VERA",\n          "FOURIERFT",\n          "XLORA",\n          "HRA",\n          "VBLORA",\n          "CPT",\n          "BONE",\n          "RANDLORA",\n          "TRAINABLE_TOKENS",\n          "C3A"\n        ],\n        "title": "PeftType",\n        "type": "string"\n      },\n      "PretrainedPeftConfig": {\n        "additionalProperties": false,\n        "description": "PEFT adapter uses the config and initialisation from a pretrained adapter",\n        "properties": {\n          "peft_type": {\n            "const": "PRETRAINED_PEFT",\n            "title": "Peft Type",\n            "type": "string"\n          },\n          "name_or_path": {\n            "description": "HF ID or path to the pretrained peft.",\n            "title": "Name Or Path",\n            "type": "string"\n          }\n        },\n        "required": [\n          "peft_type",\n          "name_or_path"\n        ],\n        "title": "PretrainedPeftConfig",\n        "type": "object"\n      },\n      "RunConfig": {\n        "additionalProperties": false,\n        "description": "Experiment running configuration",\n        "properties": {\n          "model": {\n            "default": "/local_resources/basemodel",\n            "description": "Local path to model to be fine-tuned. Normally this should be /local_resources/basemodel",\n            "title": "Model",\n            "type": "string"\n          },\n          "model_args": {\n            "$ref": "#/$defs/ModelArguments",\n            "default": {\n              "torch_dtype": "auto",\n              "device_map": "auto",\n              "max_memory": null,\n              "low_cpu_mem_usage": false,\n              "attn_implementation": null,\n              "offload_folder": null,\n              "offload_state_dict": null,\n              "offload_buffers": null,\n              "use_cache": true,\n              "cache_dir": null,\n              "force_download": false,\n              "local_files_only": false,\n              "proxies": null,\n              "resume_download": false,\n              "revision": "main",\n              "code_revision": "main",\n              "subfolder": null,\n              "token": null,\n              "use_safetensors": null,\n              "variant": null,\n              "trust_remote_code": false\n            }\n          },\n          "tokenizer": {\n            "anyOf": [\n              {\n                "type": "string"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "description": "Model HuggingFace ID, or path, or None to use the one associated with the model",\n            "title": "Tokenizer"\n          },\n          "use_fast_tokenizer": {\n            "default": true,\n            "description": "Use the Fast version of the tokenizer. The 'slow' version may be compatible with more features.",\n            "title": "Use Fast Tokenizer",\n            "type": "boolean"\n          },\n          "resume_from_checkpoint": {\n            "anyOf": [\n              {\n                "type": "boolean"\n              },\n              {\n                "type": "string"\n              }\n            ],\n            "default": false,\n            "description": "Normally should be set to 'auto' to continue if a checkpoint exists.        Can set to True to always try to continue, False to never try, or a path to load from a specific path.",\n            "title": "Resume From Checkpoint"\n          },\n          "final_checkpoint_name": {\n            "default": "checkpoint-final",\n            "description": "Name of final checkpoint. Should be left as default",\n            "title": "Final Checkpoint Name",\n            "type": "string"\n          },\n          "determinism": {\n            "default": "no",\n            "description": "Set the level of determinism in implementations. Deterministic implementations are not always available,            and when they are, they are usually slower than their non-deterministic counterparts. Recommended for            debugging only.            'no': No determinism.            'half': Prefer deterministic implementations.            'full': Only fully deterministic implementations, error out on operations that only have non-deterministic                    implementations.",\n            "enum": [\n              "no",\n              "half",\n              "full"\n            ],\n            "title": "Determinism",\n            "type": "string"\n          }\n        },\n        "title": "RunConfig",\n        "type": "object"\n      },\n      "SFTArguments": {\n        "additionalProperties": false,\n        "description": "Supervised fine-tuning arguments",\n        "properties": {\n          "max_seq_length": {\n            "default": 2048,\n            "description": "Maximum length input sequence length. Longer sequences will be filtered out.",\n            "title": "Max Seq Length",\n            "type": "integer"\n          },\n          "save_name_if_new_basemodel": {\n            "default": "checkpoint-new-basemodel",\n            "description": "If a new basemodel is saved, it will be saved with this name",\n            "title": "Save Name If New Basemodel",\n            "type": "string"\n          },\n          "train_on_completions_only": {\n            "default": false,\n            "description": "Only compute loss on the assistant's turns.",\n            "title": "Train On Completions Only",\n            "type": "boolean"\n          }\n        },\n        "title": "SFTArguments",\n        "type": "object"\n      },\n      "SFTExperimentConfig": {\n        "additionalProperties": false,\n        "description": "A full SFT experiment's config\\n\\nSee the various sub-configs for their options.",\n        "properties": {\n          "method": {\n            "const": "sft",\n            "default": "sft",\n            "title": "Method",\n            "type": "string"\n          },\n          "data_conf": {\n            "$ref": "#/$defs/ChatTrainValidConfig",\n            "description": "The data input config"\n          },\n          "training_args": {\n            "$ref": "#/$defs/SilogenTrainingArguments",\n            "description": "Transformer TrainingArguments with some restrictions"\n          },\n          "overrides": {\n            "$ref": "#/$defs/Overrides",\n            "default": {\n              "lr_multiplier": 1.0,\n              "lr_batch_size_scaling": "none"\n            },\n            "description": "Override options to simplify the config interface"\n          },\n          "batchsize_conf": {\n            "$ref": "#/$defs/BatchsizeConfig",\n            "description": "Batch size configuration"\n          },\n          "peft_conf": {\n            "anyOf": [\n              {\n                "$ref": "#/$defs/NoPeftConfig"\n              },\n              {\n                "$ref": "#/$defs/PretrainedPeftConfig"\n              },\n              {\n                "$ref": "#/$defs/GenericPeftConfig"\n              }\n            ],\n            "description": "Adapter configuration",\n            "title": "Peft Conf"\n          },\n          "run_conf": {\n            "$ref": "#/$defs/RunConfig",\n            "description": "Model related configuration"\n          },\n          "tracking": {\n            "anyOf": [\n              {\n                "$ref": "#/$defs/FinetuningTrackingConfig"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "description": "MLFlow tracking configuration"\n          },\n          "quant_conf": {\n            "anyOf": [\n              {\n                "$ref": "#/$defs/NoQuantizationConfig"\n              },\n              {\n                "$ref": "#/$defs/BnBQuantizationConfig"\n              }\n            ],\n            "default": {\n              "quantization_type": "no-quantization"\n            },\n            "description": "Quantization configuration",\n            "title": "Quant Conf"\n          },\n          "sft_args": {\n            "$ref": "#/$defs/SFTArguments",\n            "description": "SFT specific arguments"\n          }\n        },\n        "required": [\n          "data_conf",\n          "training_args",\n          "batchsize_conf",\n          "peft_conf",\n          "run_conf",\n          "sft_args"\n        ],\n        "title": "SFTExperimentConfig",\n        "type": "object"\n      },\n      "SaveStrategy": {\n        "enum": [\n          "no",\n          "steps",\n          "epoch",\n          "best"\n        ],\n        "title": "SaveStrategy",\n        "type": "string"\n      },\n      "SchedulerType": {\n        "description": "Scheduler names for the parameter `lr_scheduler_type` in [`TrainingArguments`].\\nBy default, it uses \\"linear\\". Internally, this retrieves `get_linear_schedule_with_warmup` scheduler from [`Trainer`].\\nScheduler types:\\n   - \\"linear\\" = get_linear_schedule_with_warmup\\n   - \\"cosine\\" = get_cosine_schedule_with_warmup\\n   - \\"cosine_with_restarts\\" = get_cosine_with_hard_restarts_schedule_with_warmup\\n   - \\"polynomial\\" = get_polynomial_decay_schedule_with_warmup\\n   - \\"constant\\" =  get_constant_schedule\\n   - \\"constant_with_warmup\\" = get_constant_schedule_with_warmup\\n   - \\"inverse_sqrt\\" = get_inverse_sqrt_schedule\\n   - \\"reduce_lr_on_plateau\\" = get_reduce_on_plateau_schedule\\n   - \\"cosine_with_min_lr\\" = get_cosine_with_min_lr_schedule_with_warmup\\n   - \\"warmup_stable_decay\\" = get_wsd_schedule",\n        "enum": [\n          "linear",\n          "cosine",\n          "cosine_with_restarts",\n          "polynomial",\n          "constant",\n          "constant_with_warmup",\n          "inverse_sqrt",\n          "reduce_lr_on_plateau",\n          "cosine_with_min_lr",\n          "warmup_stable_decay"\n        ],\n        "title": "SchedulerType",\n        "type": "string"\n      },\n      "SilogenDPOConfig": {\n        "additionalProperties": false,\n        "properties": {\n          "output_dir": {\n            "default": "checkpoints",\n            "description": "The output directory where checkpoints will be written. Should be left as default, which is ./checkpoints",\n            "title": "Output Dir",\n            "type": "string"\n          },\n          "overwrite_output_dir": {\n            "default": false,\n            "title": "Overwrite Output Dir",\n            "type": "boolean"\n          },\n          "do_train": {\n            "default": false,\n            "title": "Do Train",\n            "type": "boolean"\n          },\n          "do_eval": {\n            "default": false,\n            "title": "Do Eval",\n            "type": "boolean"\n          },\n          "do_predict": {\n            "default": false,\n            "title": "Do Predict",\n            "type": "boolean"\n          },\n          "eval_strategy": {\n            "anyOf": [\n              {\n                "$ref": "#/$defs/IntervalStrategy"\n              },\n              {\n                "type": "string"\n              }\n            ],\n            "default": "no",\n            "title": "Eval Strategy"\n          },\n          "prediction_loss_only": {\n            "default": false,\n            "title": "Prediction Loss Only",\n            "type": "boolean"\n          },\n          "per_device_train_batch_size": {\n            "default": -1,\n            "description": "Input is disallowed, this will computed from the batchsize config",\n            "title": "Per Device Train Batch Size"\n          },\n          "per_device_eval_batch_size": {\n            "default": -1,\n            "description": "Input is disallowed, this will computed from the batchsize config",\n            "title": "Per Device Eval Batch Size"\n          },\n          "per_gpu_train_batch_size": {\n            "anyOf": [\n              {\n                "type": "integer"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "title": "Per Gpu Train Batch Size"\n          },\n          "per_gpu_eval_batch_size": {\n            "anyOf": [\n              {\n                "type": "integer"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "title": "Per Gpu Eval Batch Size"\n          },\n          "gradient_accumulation_steps": {\n            "default": -1,\n            "description": "Input is disallowed, this will computed from the batchsize config",\n            "title": "Gradient Accumulation Steps"\n          },\n          "eval_accumulation_steps": {\n            "anyOf": [\n              {\n                "type": "integer"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "title": "Eval Accumulation Steps"\n          },\n          "eval_delay": {\n            "anyOf": [\n              {\n                "type": "number"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": 0,\n            "title": "Eval Delay"\n          },\n          "torch_empty_cache_steps": {\n            "anyOf": [\n              {\n                "type": "integer"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "title": "Torch Empty Cache Steps"\n          },\n          "learning_rate": {\n            "default": 1e-06,\n            "title": "Learning Rate",\n            "type": "number"\n          },\n          "weight_decay": {\n            "default": 0.0,\n            "title": "Weight Decay",\n            "type": "number"\n          },\n          "adam_beta1": {\n            "default": 0.9,\n            "title": "Adam Beta1",\n            "type": "number"\n          },\n          "adam_beta2": {\n            "default": 0.999,\n            "title": "Adam Beta2",\n            "type": "number"\n          },\n          "adam_epsilon": {\n            "default": 1e-08,\n            "title": "Adam Epsilon",\n            "type": "number"\n          },\n          "max_grad_norm": {\n            "default": 1.0,\n            "title": "Max Grad Norm",\n            "type": "number"\n          },\n          "num_train_epochs": {\n            "default": 3.0,\n            "title": "Num Train Epochs",\n            "type": "number"\n          },\n          "max_steps": {\n            "default": -1,\n            "title": "Max Steps",\n            "type": "integer"\n          },\n          "lr_scheduler_type": {\n            "anyOf": [\n              {\n                "$ref": "#/$defs/SchedulerType"\n              },\n              {\n                "type": "string"\n              }\n            ],\n            "default": "linear",\n            "title": "Lr Scheduler Type"\n          },\n          "lr_scheduler_kwargs": {\n            "anyOf": [\n              {\n                "type": "string"\n              },\n              {\n                "additionalProperties": true,\n                "type": "object"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "title": "Lr Scheduler Kwargs"\n          },\n          "warmup_ratio": {\n            "default": 0.0,\n            "title": "Warmup Ratio",\n            "type": "number"\n          },\n          "warmup_steps": {\n            "default": 0,\n            "title": "Warmup Steps",\n            "type": "integer"\n          },\n          "log_level": {\n            "default": "passive",\n            "title": "Log Level",\n            "type": "string"\n          },\n          "log_level_replica": {\n            "default": "warning",\n            "title": "Log Level Replica",\n            "type": "string"\n          },\n          "log_on_each_node": {\n            "default": true,\n            "title": "Log On Each Node",\n            "type": "boolean"\n          },\n          "logging_dir": {\n            "anyOf": [\n              {\n                "type": "string"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "title": "Logging Dir"\n          },\n          "logging_strategy": {\n            "anyOf": [\n              {\n                "$ref": "#/$defs/IntervalStrategy"\n              },\n              {\n                "type": "string"\n              }\n            ],\n            "default": "steps",\n            "title": "Logging Strategy"\n          },\n          "logging_first_step": {\n            "default": false,\n            "title": "Logging First Step",\n            "type": "boolean"\n          },\n          "logging_steps": {\n            "default": 500,\n            "title": "Logging Steps",\n            "type": "number"\n          },\n          "logging_nan_inf_filter": {\n            "default": true,\n            "title": "Logging Nan Inf Filter",\n            "type": "boolean"\n          },\n          "save_strategy": {\n            "anyOf": [\n              {\n                "$ref": "#/$defs/SaveStrategy"\n              },\n              {\n                "type": "string"\n              }\n            ],\n            "default": "steps",\n            "title": "Save Strategy"\n          },\n          "save_steps": {\n            "default": 500,\n            "title": "Save Steps",\n            "type": "number"\n          },\n          "save_total_limit": {\n            "anyOf": [\n              {\n                "type": "integer"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "title": "Save Total Limit"\n          },\n          "save_safetensors": {\n            "anyOf": [\n              {\n                "type": "boolean"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": true,\n            "title": "Save Safetensors"\n          },\n          "save_on_each_node": {\n            "default": false,\n            "title": "Save On Each Node",\n            "type": "boolean"\n          },\n          "save_only_model": {\n            "default": false,\n            "title": "Save Only Model",\n            "type": "boolean"\n          },\n          "restore_callback_states_from_checkpoint": {\n            "default": false,\n            "title": "Restore Callback States From Checkpoint",\n            "type": "boolean"\n          },\n          "no_cuda": {\n       