r"\n          },\n          "dataloader_prefetch_factor": {\n            "anyOf": [\n              {\n                "type": "integer"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "title": "Dataloader Prefetch Factor"\n          },\n          "past_index": {\n            "default": -1,\n            "title": "Past Index",\n            "type": "integer"\n          },\n          "run_name": {\n            "anyOf": [\n              {\n                "type": "string"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "title": "Run Name"\n          },\n          "disable_tqdm": {\n            "anyOf": [\n              {\n                "type": "boolean"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "title": "Disable Tqdm"\n          },\n          "remove_unused_columns": {\n            "anyOf": [\n              {\n                "type": "boolean"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": true,\n            "title": "Remove Unused Columns"\n          },\n          "label_names": {\n            "anyOf": [\n              {\n                "items": {\n                  "type": "string"\n                },\n                "type": "array"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "title": "Label Names"\n          },\n          "load_best_model_at_end": {\n            "anyOf": [\n              {\n                "type": "boolean"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": false,\n            "title": "Load Best Model At End"\n      