  "type": "integer"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "title": "Tpu Num Cores"\n          },\n          "tpu_metrics_debug": {\n            "default": false,\n            "title": "Tpu Metrics Debug",\n            "type": "boolean"\n          },\n          "debug": {\n            "anyOf": [\n              {\n                "type": "string"\n              },\n              {\n                "items": {\n                  "$ref": "#/$defs/DebugOption"\n                },\n                "type": "array"\n              }\n            ],\n            "default": "",\n            "title": "Debug"\n          },\n          "dataloader_drop_last": {\n            "default": false,\n            "title": "Dataloader Drop Last",\n            "type": "boolean"\n          },\n          "eval_steps": {\n            "anyOf": [\n              {\n                "type": "number"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "title": "Eval Steps"\n          },\n          "dataloader_num_workers": {\n            "default": 0,\n            "title": "Dataloader Num Workers",\n            "type": "integer"\n          },\n          "dataloader_prefetch_factor": {\n            "anyOf": [\n              {\n                "type": "integer"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "title": "Dataloader Prefetch Factor"\n          },\n          "past_index": {\n            "default": -1,\n            "title": "Past Index",\n            "type": "integer"\n          },\n          "run_name": {\n            "anyOf": [\n              {\n                "type": "string"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "title": "Run Name"\n          },\n          "disable_tqdm": {\n            "anyOf": [\n              {\n                "type": "boolean"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "title": "Disable Tqdm"\n          },\n          "remove_unused_columns": {\n            "anyOf": [\n              {\n                "type": "boolean"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": true,\n            "title": "Remove Unused Columns"\n          },\n          "label_names": {\n            "anyOf": [\n              {\n                "items": {\n                  "type": "string"\n                },\n                "type": "array"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "title": "Label Names"\n          },\n          "load_best_model_at_end": {\n            "anyOf": [\n              {\n                "type": "boolean"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": false,\n            "title": "Load Best Model At End"\n          },\n          "metric_for_best_model": {\n            "anyOf": [\n              {\n                "type": "string"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "title": "Metric For Best Model"\n          },\n          "greater_is_better": {\n            "anyOf": [\n              {\n                "type": "boolean"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "title": "Greater Is Better"\n          },\n          "ignore_data_skip": {\n            "default": false,\n            "title": "Ignore Data Skip",\n            "type": "boolean"\n          },\n          "fsdp": {\n            "anyOf": [\n              {\n                "items": {\n                  "$ref": "#/$defs/FSDPOption"\n                },\n                "type": "array"\n              },\n              {\n                "type": "string"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": "",\n            "title": "Fsdp"\n          },\n          "fsdp_min_num_params": {\n            "default": 0,\n            "title": "Fsdp Min Num Params",\n            "type": "integer"\n          },\n          "fsdp_config": {\n            "anyOf": [\n              {\n                "additionalProperties": true,\n                "type": "object"\n              },\n              {\n                "type": "string"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "title": "Fsdp Config"\n          },\n          "fsdp_transformer_layer_cls_to_wrap": {\n            "anyOf": [\n              {\n                "type": "string"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "title": "Fsdp Transformer Layer Cls To Wrap"\n          },\n          "accelerator_config": {\n            "anyOf": [\n              {\n                "type": "string"\n              },\n              {\n                "additionalProperties": true,\n                "type": "object"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "title": "Accelerator Config"\n          },\n          "deepspeed": {\n            "anyOf": [\n              {\n                "type": "string"\n              },\n              {\n                "additionalProperties": true,\n                "type": "object"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "title": "Deepspeed"\n          },\n          "label_smoothing_factor": {\n            "default": 0.0,\n            "title": "Label Smoothing Factor",\n            "type": "number"\n          },\n          "optim": {\n            "anyOf": [\n              {\n                "$ref": "#/$defs/OptimizerNames"\n              },\n              {\n                "type": "string"\n              }\n            ],\n            "default": "adamw_torch",\n            "title": "Optim"\n          },\n          "optim_args": {\n            "anyOf": [\n              {\n                "type": "string"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "title": "Optim Args"\n          },\n          "adafactor": {\n            "default": false,\n            "title": "Adafactor",\n            "type": "boolean"\n          },\n          "group_by_length": {\n            "default": false,\n            "title": "Group By Length",\n            "type": "boolean"\n          },\n          "length_column_name": {\n            "anyOf": [\n              {\n                "type": "string"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": "length",\n            "title": "Length Column Name"\n          },\n          "report_to": {\n            "anyOf": [\n              {\n                "type": "string"\n              },\n              {\n                "items": {\n                  "type": "string"\n                },\n                "type": "array"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "title": "Report To"\n          },\n          "ddp_find_unused_parameters": {\n            "anyOf": [\n              {\n                "type": "boolean"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "title": "Ddp Find Unused Parameters"\n          },\n          "ddp_bucket_cap_mb": {\n            "anyOf": [\n              {\n                "type": "integer"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "title": "Ddp Bucket Cap Mb"\n          },\n          "ddp_broadcast_buffers": {\n            "anyOf": [\n              {\n                "type": "boolean"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "title": "Ddp Broadcast Buffers"\n          },\n          "dataloader_pin_memory": {\n            "default": true,\n            "title": "Dataloader Pin Memory",\n            "type": "boolean"\n          },\n          "dataloader_persistent_workers": {\n            "default": false,\n            "title": "Dataloader Persistent Workers",\n            "type": "boolean"\n          },\n          "skip_memory_metrics": {\n            "default": true,\n            "title": "Skip Memory Metrics",\n            "type": "boolean"\n          },\n          "use_legacy_prediction_loop": {\n            "default": false,\n            "title": "Use Legacy Prediction Loop",\n            "type": "boolean"\n          },\n          "push_to_hub": {\n            "default": false,\n            "title": "Push To Hub",\n            "type": "boolean"\n          },\n          "resume_from_checkpoint": {\n            "anyOf": [\n              {\n                "type": "string"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "title": "Resume From Checkpoint"\n          },\n          "hub_model_id": {\n            "anyOf": [\n              {\n                "type": "string"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "title": "Hub Model Id"\n          },\n          "hub_strategy": {\n            "anyOf": [\n              {\n                "$ref": "#/$defs/HubStrategy"\n              },\n              {\n                "type": "string"\n              }\n            ],\n            "default": "every_save",\n            "title": "Hub Strategy"\n          },\n          "hub_token": {\n            "anyOf": [\n              {\n                "type": "string"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "title": "Hub Token"\n          },\n          "hub_private_repo": {\n            "anyOf": [\n              {\n                "type": "boolean"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "title": "Hub Private Repo"\n          },\n          "hub_always_push": {\n            "default": false,\n            "title": "Hub Always Push",\n            "type": "boolean"\n          },\n          "hub_revision": {\n            "anyOf": [\n              {\n                "type": "string"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "title": "Hub Revision"\n          },\n          "gradient_checkpointing": {\n            "default": false,\n            "title": "Gradient Checkpointing",\n            "type": "boolean"\n          },\n          "gradient_checkpointing_kwargs": {\n            "anyOf": [\n              {\n                "additionalProperties": true,\n                "type": "object"\n              },\n              {\n                "type": "string"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "title": "Gradient Checkpointing Kwargs"\n          },\n          "include_inputs_for_metrics": {\n            "default": false,\n            "title": "Include Inputs For Metrics",\n            "type": "boolean"\n          },\n          "include_for_metrics": {\n            "items": {\n              "type": "string"\n            },\n            "title": "Include For Metrics",\n            "type": "array"\n          },\n          "eval_do_concat_batches": {\n            "default": true,\n            "title": "Eval Do Concat Batches",\n            "type": "boolean"\n          },\n          "fp16_backend": {\n            "default": "auto",\n            "title": "Fp16 Backend",\n            "type": "string"\n          },\n          "push_to_hub_model_id": {\n            "anyOf": [\n              {\n                "type": "string"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "title": "Push To Hub Model Id"\n          },\n          "push_to_hub_organization": {\n            "anyOf": [\n              {\n                "type": "string"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "title": "Push To Hub Organization"\n          },\n          "push_to_hub_token": {\n            "anyOf": [\n              {\n                "type": "string"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "title": "Push To Hub Token"\n          },\n          "mp_parameters": {\n            "default": "",\n            "title": "Mp Parameters",\n            "type": "string"\n          },\n          "auto_find_batch_size": {\n            "default": false,\n            "title": "Auto Find Batch Size",\n            "type": "boolean"\n          },\n          "full_determinism": {\n            "default": false,\n            "title": "Full Determinism",\n            "type": "boolean"\n          },\n          "torchdynamo": {\n            "anyOf": [\n              {\n                "type": "string"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "title": "Torchdynamo"\n          },\n          "ray_scope": {\n            "anyOf": [\n              {\n                "type": "string"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": "last",\n            "title": "Ray Scope"\n          },\n          "ddp_timeout": {\n            "default": 1800,\n            "title": "Ddp Timeout",\n            "type": "integer"\n          },\n          "torch_compile": {\n            "default": false,\n            "title": "Torch Compile",\n            "type": "boolean"\n          },\n          "torch_compile_backend": {\n            "anyOf": [\n              {\n                "type": "string"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "title": "Torch Compile Backend"\n          },\n          "torch_compile_mode": {\n            "anyOf": [\n              {\n                "type": "string"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "title": "Torch Compile Mode"\n          },\n          "include_tokens_per_second": {\n            "anyOf": [\n              {\n                "type": "boolean"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": false,\n            "title": "Include Tokens Per Second"\n          },\n          "include_num_input_tokens_seen": {\n            "anyOf": [\n              {\n                "type": "boolean"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": false,\n            "title": "Include Num Input Tokens Seen"\n          },\n          "neftune_noise_alpha": {\n            "anyOf": [\n              {\n                "type": "number"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "title": "Neftune Noise Alpha"\n          },\n          "optim_target_modules": {\n            "anyOf": [\n              {\n                "type": "string"\n              },\n              {\n                "items": {\n                  "type": "string"\n                },\n                "type": "array"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "title": "Optim Target Modules"\n          },\n          "batch_eval_metrics": {\n            "default": false,\n            "title": "Batch Eval Metrics",\n            "type": "boolean"\n          },\n          "eval_on_start": {\n            "default": false,\n            "title": "Eval On Start",\n            "type": "boolean"\n          },\n          "use_liger_kernel": {\n            "anyOf": [\n              {\n                "type": "boolean"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": false,\n            "title": "Use Liger Kernel"\n          },\n          "liger_kernel_config": {\n            "anyOf": [\n              {\n                "additionalProperties": {\n                  "type": "boolean"\n                },\n                "type": "object"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": null,\n            "title": "Liger Kernel Config"\n          },\n          "eval_use_gather_object": {\n            "anyOf": [\n              {\n                "type": "boolean"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": false,\n            "title": "Eval Use Gather Object"\n          },\n          "average_tokens_across_devices": {\n            "anyOf": [\n              {\n                "type": "boolean"\n              },\n              {\n                "type": "null"\n              }\n            ],\n            "default": false,\n            "title": "Average Tokens Across Devices"\n          }\n        },\n        "title": "SilogenTrainingArguments",\n        "type": "object"\n      },\n      "TaskType": {\n        "description": "Enum class for the different types of tasks supported by PEFT.\\n\\nOverview of the supported task types:\\n- SEQ_CLS: Text classification.\\n- SEQ_2_SEQ_LM: Sequence-to-sequence language modeling.\\n- CAUSAL_LM: Causal language modeling.\\n- TOKEN_CLS: Token classification.\\n- QUESTION_ANS: Question answering.\\n- FEATURE_EXTRACTION: Feature extraction. Provides the hidden states which can be used as embeddings or features\\n  for downstream tasks.",\n        "enum": [\n          "SEQ_CLS",\n          "SEQ_2_SEQ_LM",\n          "CAUSAL_LM",\n          "TOKEN_CLS",\n          "QUESTION_ANS",\n          "FEATURE_EXTRACTION"\n        ],\n        "title": "TaskType",\n        "type": "string"\n      },\n      "WeightedDatasetDefinition": {\n        "additionalProperties": false,\n        "description": "Define a dataset, with a weight for sampling",\n        "properties": {\n          "path": {\n            "description": "Local path to a JSONL file in the finetuning data format",\n            "title": "Path",\n            "type": "string"\n          },\n          "sampling_weight": {\n            "default": 1.0,\n            "title": "Sampling Weight",\n            "type": "number"\n          }\n        },\n        "required": [\n          "path"\n        ],\n        "title": "WeightedDatasetDefinition",\n        "type": "object"\n      },\n      "WeightedMixDataInput": {\n        "additionalProperties": false,\n        "description": "A list of datasets where each is sampled by a certain weight\\n\\nThese datasets are interleaved based on the sampling weights. The resulting dataset is fully precomputed, upto\\nthe point where every single sample in every dataset gets picked. This means that with small sampling weights,\\nit can take a lot of draws to see every sample from a dataset and so the resulting dataset can be very large.\\n\\nThe datasets themselves need to be in the finetuning supported JSONL formats.\\nFor SFT this means lines:\\n\\n    {\\"messages\\": {\\"content\\": \\"string\\", \\"role\\": \\"string\\"}}\\n\\nFor DPO this means lines of:\\n\\n    {\\"prompt_messages\\": {\\"content\\": \\"string\\", \\"role\\": \\"string\\"}, \\"chosen_messages\\": {\\"content\\": \\"string\\", \\"role\\": \\"string\\"}, \\"rejected_messages\\": {\\"content\\": \\"string\\", \\"role\\": \\"string\\"}}",\n        "properties": {\n          "type": {\n            "const": "PRECOMPUTE_WEIGHTED_MIX",\n            "title": "Type",\n            "type": "string"\n          },\n          "data_type": {\n            "default": "ChatConversation",\n            "description": "Generally, the data_type is automatically set based on the experiment config method.",\n            "title": "Data Type",\n            "type": "string"\n          },\n          "datasets": {\n            "items": {\n              "$ref": "#/$defs/WeightedDatasetDefinition"\n            },\n            "minItems": 1,\n            "title": "Datasets",\n            "type": "array"\n          },\n          "seed": {\n            "default": 19851243,\n            "description": "Seed for the random number generator for interleaving draws",\n            "title": "Seed",\n            "type": "integer"\n          }\n        },\n        "required": [\n          "type",\n          "datasets"\n        ],\n        "title": "WeightedMixDataInput",\n        "type": "object"\n      }\n    }\n}\n	4d4c0334-f713-4550-a99c-22f3ecdcf5b8	2026-03-17 12:30:30.860134+00	2026-03-17 12:30:30.860135+00	system	system
b426dc64-8c60-43c1-8d9d-5762d91e94ab	Chart.yaml	apiVersion: v2\nname: llm-finetune-silogen-engine\ndescription: A Helm chart for fine-tuning the Silogen engine\nversion: 0.0.1\n	4d4c0334-f713-4550-a99c-22f3ecdcf5b8	2026-03-17 12:30:30.860139+00	2026-03-17 12:30:30.860139+00	system	system
73cb8c4d-3649-4ac5-b216-d120ccbae4ba	values.yaml	### General chart values ###\nfinetuningImage: ghcr.io/silogen/rocm-silogen-finetuning-worker:v0.4\n\n# kaiwo settings (if enabled, use kaiwo CRDs to have kaiwo operator manage the workload)\nkaiwo:\n  enabled: false\n\n# Use to add labels to the metadata of the resources created by this workload.\nlabels: {}\n\n# Extra annotations such as an imagePullSecrets\nimagePullSecrets: []\n  # Example:\n  # imagePullSecrets:\n  #   - "regcred"\n\n# Configure these to match the credentials in your cluster:\nbucketStorageHost: http://minio.minio-tenant-default.svc.cluster.local:80\nbucketCredentialsSecret:\n  name: minio-credentials\n  accessKeyKey: minio-access-key\n  secretKeyKey: minio-secret-key\n\n# Resources:\ndownloadsReservedSize: 64Gi\ncheckpointsReservedSize: 512Gi\nstorageClass: mlstorage # set this to use a specific storageClass for the storage.\nfinetuningGpus: 1 # 1 or 8, values in between are not robust at the moment\nmemoryPerGpu: 64\ncpusPerGpu: 8\n\n# Runtime configuration:\ndistributedType: "auto-deepspeed-stage1"  # Alternatives: "auto-deepspeed-stage3", "auto-ddp", "auto-single-process", "custom-accelerate-config"\ncustomAccelerateConfig:  # Can contain an accelerate config in YAML format, used with distributed_type: "custom-accelerate-config".\nmergeAdapter: true\n\n### Model input and output, required args ###\ncheckpointsRemote:  # Path where to sync checkpoints in bucket storage, format: bucketName/path/in/bucket)\nbasemodel:  # Path to basemodel directory in the bucket storage\n# Auxiliary model download args:\nmodel: "" # Canonical model name, e.g. "meta-llama/llama-3.1-8b-instruct" or "OdiaGenAI-LLM/qwen_1.5_odia_7b"\nhfDownloadExcludeGlob: ""\nhfTokenSecret:\n# Example:\n# hfTokenSecret:\n#   name: hf-token\n#   key: hf-token\n\n# Reporting\n# Set runTensorboard to true to run tensorboard in the background in the same container.\n# Also remember to set report_to: tensorboard in the finetuning_config.training_args section.\nrunTensorboard: false\nlogsRemote: # Path where to sync logs in bucket storage (defaults to <checkpointsRemote>/logs if not set), format: bucktetName/path/in/bucket\n\n\n### Finetuning config section ###\nfinetuning_config:\n  method: sft\n  data_conf:\n    training_data:\n      type: CONCATENATION # CONCATENATION | PRECOMPUTE_WEIGHTED_MIX\n      datasets: []\n    validation_data:\n      type: AUTO_SPLIT # AUTO_SPLIT | CONCATENATION | NONE\n      ratio: 0.1\n    chat_template_name: "keep-original"  # "keep-original" | "simplified-llama31" | "chat-ml"\n    missing_pad_token_strategy: "bos-repurpose"  # "bos-repurpose" | "unk-repurpose"\n  training_args: {}\n    # training_args is like Huggingface TrainingArguments, but certain inputs are not allowed:\n    # - Do not set output_dir, the checkpoints should be saved to the default location to be uploaded\n    # - Do not set per_device_train_batch_size nor gradient_accumulation, they are automatically set\n    #   based on the batchsize_conf (below)\n  overrides:\n    lr_multiplier: 1.0\n    lr_batch_size_scaling: "none"\n  batchsize_conf:\n    total_train_batch_size:  # By default, this gets set to the number of GPUs\n    max_per_device_train_batch_size: 1\n    per_device_eval_batch_size: # By default is the same as per_device_train_batch_size\n  peft_conf:\n    peft_type: NO_PEFT\n      # This can be any HF peft_type or NO_PEFT.\n      # If setting peft_type for any actual PEFT, also set:\n      # task_type: "CAUSAL_LM", or some other task type, but usually this.\n      # peft_kwargs:, the huggingface kwargs for the that PEFT model type\n  quant_conf:\n    quantization_type: no-quantization\n      # This can also be bitsandbytes\n      # If bitsandbytes, you can also set any keys from BitsAndBytesConfig here\n  run_conf:\n    model_args: {}  # These are HuggingFace model .from_pretrained() kwargs\n    resume_from_checkpoint: auto\n  sft_args:\n    max_seq_length: 2048\n  tracking: null\n	4d4c0334-f713-4550-a99c-22f3ecdcf5b8	2026-03-17 12:30:30.860141+00	2026-03-17 12:30:30.860142+00	system	system
ecc09837-dc9a-4577-8a21-243e873cbfc4	templates/job.yaml	{{- define "job" -}}\napiVersion: batch/v1\nkind: Job\nmetadata:\n  name: "{{ .Release.Name }}-job"\n  {{- if .Values.labels }}\n  labels:\n    {{- range $label, $value := .Values.labels }}\n    {{ $label }}: {{ $value | quote }}\n    {{- end }}\n  {{- end }}\nspec:\n  ttlSecondsAfterFinished: 86400  #24h\n  backoffLimit: 0\n  template:\n    spec:\n      restartPolicy: Never\n      {{- if .Values.imagePullSecrets }}\n      imagePullSecrets:\n        {{- range .Values.imagePullSecrets }}\n        - name: {{ . }}\n        {{- end }}\n      {{- end }}\n      containers:\n        - name: finetuning\n          image: "{{ .Values.finetuningImage }}"\n          imagePullPolicy: Always\n          env:\n            # download\n            {{- if .Values.hfTokenSecret }}\n            - name: HF_TOKEN\n              valueFrom:\n                secretKeyRef:\n                  name: {{ .Values.hfTokenSecret.name }}\n                  key: {{ .Values.hfTokenSecret.key }}\n            {{- end }}\n            - name: BUCKET_STORAGE_HOST\n              value: {{ .Values.bucketStorageHost }}\n            - name: BUCKET_STORAGE_ACCESS_KEY\n              valueFrom:\n                secretKeyRef:\n                  name: {{ .Values.bucketCredentialsSecret.name }}\n                  key: {{ .Values.bucketCredentialsSecret.accessKeyKey }}\n            - name: BUCKET_STORAGE_SECRET_KEY\n              valueFrom:\n                secretKeyRef:\n                  name: {{ .Values.bucketCredentialsSecret.name }}\n                  key: {{ .Values.bucketCredentialsSecret.secretKeyKey }}\n            # finetuning logging\n            - name: ACCELERATE_LOG_LEVEL\n              value: info\n            - name: TRANSFORMERS_VERBOSITY\n              value: info\n          command:\n            - /bin/bash\n            - -l\n            - -e\n            - -u\n            - -c\n          args:\n            - |\n              echo '===== Download ====='\n              {{- include "downloadEntrypoint" . | nindent 14 }}\n              echo '===== Finetuning and Checkpoint Upload ====='\n              {{- include "finetuningAndUploadEntrypoint" . | nindent 14 }}\n          resources:\n            limits:\n              memory: "{{ mul .Values.finetuningGpus .Values.memoryPerGpu }}Gi"\n              cpu: "{{ mul .Values.finetuningGpus .Values.cpusPerGpu }}"\n              amd.com/gpu: "{{ .Values.finetuningGpus }}"\n            requests:\n              memory: "{{ mul .Values.finetuningGpus .Values.memoryPerGpu }}Gi"\n              cpu: "{{ mul .Values.finetuningGpus .Values.cpusPerGpu }}"\n              amd.com/gpu: "{{ .Values.finetuningGpus }}"\n          volumeMounts:\n            - name: dshm # Increase SHM size for the container by mounting /dev/shm, for Pytorch parallel processing\n              mountPath: /dev/shm\n            - name: downloads\n              mountPath: /local_resources\n              readOnly: false\n            - name: checkpoints\n              mountPath: /workdir/checkpoints\n              readOnly: false\n            - name: semaphores\n              mountPath: /semaphores\n              readOnly: false\n            - name: configs\n              mountPath: /configs\n              readOnly: true\n          securityContext:\n            allowPrivilegeEscalation: false\n            runAsNonRoot: true\n            runAsUser: 1000\n            seccompProfile:\n              type: RuntimeDefault\n            capabilities:\n              drop: ["ALL"]\n      securityContext:\n        fsGroup: 1000\n      volumes:\n        - name: dshm\n          emptyDir:\n            medium: Memory # equivalent to `docker run --shm-size=(total_memory/2)`\n        {{- if .Values.storageClass }}\n        - name: downloads\n          ephemeral:\n            volumeClaimTemplate:\n              spec:\n                accessModes: [ "ReadWriteOnce" ]\n                storageClassName: {{ .Values.storageClass }}\n                resources:\n                  requests:\n                    storage: "{{ .Values.downloadsReservedSize }}"\n        - name: checkpoints\n          ephemeral:\n            volumeClaimTemplate:\n              spec:\n                accessModes: [ "ReadWriteOnce" ]\n                storageClassName: {{ .Values.storageClass }}\n                resources:\n                  requests:\n                    storage: "{{ .Values.checkpointsReservedSize }}"\n        {{- else }}\n        - name: downloads\n          emptyDir:\n            sizeLimit: "{{ .Values.downloadsReservedSize }}"\n        - name: checkpoints\n          emptyDir:\n            sizeLimit: "{{ .Values.checkpointsReservedSize }}"\n        {{- end }}\n        - name: semaphores\n          emptyDir:\n            medium: Memory\n            sizeLimit: "10Mi"\n        - name: configs\n          configMap:\n            name: "{{ .Release.Name }}-configs"\n{{- end -}}\n\n{{- define "job_wrapped_with_kaiwojob" -}}\napiVersion: kaiwo.silogen.ai/v1alpha1\nkind: KaiwoJob\nmetadata:\n  name: "{{ .Release.Name }}-job"\nspec:\n  job:\n    {{- include "job" . | nindent 4 }}\n{{- end -}}\n\n{{- if .Values.kaiwo.enabled -}}\n{{- include "job_wrapped_with_kaiwojob" . }}\n{{- else -}}\n{{- include "job" . }}\n{{- end -}}\n	4d4c0334-f713-4550-a99c-22f3ecdcf5b8	2026-03-17 12:30:30.860144+00	2026-03-17 12:30:30.860144+00	system	system
a6fb3e7f-38d1-4a89-bf59-8add27a60792	templates/_helpers.tpl	{/* ####################################################################################################################################################### */}}\n{{- define "downloadEntrypoint" -}}\n# Setup MinIO, Download resources:\necho 'Copying resources to container...';\nmc alias set minio-host $${BUCKET_STORAGE_HOST} $${BUCKET_STORAGE_ACCESS_KEY} $${BUCKET_STORAGE_SECRET_KEY}\n{{- if (hasPrefix "hf://" .Values.basemodel) }}\nhuggingface-cli download '{{ trimPrefix "hf://" .Values.basemodel }}' \\\n  {{- if .Values.hfDownloadExcludeGlob }}\n  --exclude '{{ .Values.hfDownloadExcludeGlob }}' \\\n  {{- end }}\n  --local-dir /local_resources/basemodel\n{{- else }}\nmc cp --recursive \\\n  minio-host/'{{ .Values.basemodel | trimSuffix "/" }}'/ \\\n  /local_resources/basemodel\n{{- end }}\n{{- if $.Values.trainingData }}\nmc cp \\\n  minio-host/'{{ $.Values.trainingData | replace  "'" "'\\\\''" }}' \\\n  /local_resources/'{{ $.Values.trainingData | replace  "'" "'\\\\''" | replace "/" "_" }}'\n{{- else }}\n{{- range .Values.finetuning_config.data_conf.training_data.datasets }}\nmc cp \\\n  minio-host/'{{ .path | replace  "'" "'\\\\''" }}' \\\n  /local_resources/'{{ .path | replace  "'" "'\\\\''" | replace "/" "_" }}'\n{{- end }}\n{{- if (or (eq .Values.finetuning_config.data_conf.validation_data.type "AUTO_SPLIT" ) (eq .Values.finetuning_config.data_conf.validation_data.type "NONE")) }}\n{{- range .Values.finetuning_config.data_conf.validation_data.datasets }}\nmc cp \\\n  minio-host/'{{ .path | replace  "'" "'\\\\''" }}' \\\n  /local_resources/'{{ .path | replace  "'" "'\\\\''" | replace "/" "_" }}'\n{{- end }}\n{{- end }}\n{{- end }}\n# Sync checkpoints from remote to local\n{{- $checkpointsRemotePath := printf "minio-host/'%s'/" (.Values.checkpointsRemote | trimSuffix "/" | replace  "'" "'\\\\''") }}\nif mc mirror {{ $checkpointsRemotePath }} /workdir/checkpoints 2>/dev/null; then\n  echo 'Downloaded checkpoints from {{ .Values.checkpointsRemote | trimSuffix "/" | replace  "'" "'\\\\''" }} to /workdir/checkpoints'\n  ls -lah /workdir/checkpoints\nelse\n  echo 'No checkpoints found yet'\nfi\n{{- end }}\n\n{/* ####################################################################################################################################################### */}}\n{{- define "finetuningAndUploadEntrypoint" -}}\n# quote paths with single quotes to avoid issues with special characters in paths, and replace any existing single quote with escaped single quote\n{{- $checkpointsRemotePath := printf "minio-host/'%s'/" (.Values.checkpointsRemote | trimSuffix "/" | replace  "'" "'\\\\''") }}\n{{- $logsRemotePath := printf "minio-host/'%s'/" ( (default ( .Values.checkpointsRemote | trimSuffix "/" | printf "%s/logs" ) .Values.logsRemote ) | trimSuffix "/" | replace  "'" "'\\\\''") -}}\n# Print GPU Info:\nrocm-smi\necho "Starting checkpoint sync process"\nmc mirror \\\n  --watch \\\n  /workdir/checkpoints \\\n  {{ $checkpointsRemotePath }} &\nuploadPID=$!\nsleep 1 # Give some time for the process to start\n# Check if the sync process started successfully\nif ! ps -p $uploadPID > /dev/null; then\n  echo "ERROR: Sync process failed to start"\n  exit 1\nfi\n# Run training:\n{{- if .Values.runTensorboard }}\ntensorboard --logdir /workdir/logs --port 6006 &\necho "Serving tensorboard on port 6006. Port-forward to access training logs during the training process lifetime."\necho "Also starting logs upload process, uploading to {{ $logsRemotePath }}"\nmc mirror \\\n  --watch \\\n  /workdir/logs \\\n  {{ $logsRemotePath }} &\nlogsPID=$!\nsleep 1\nif ! ps -p $logsPID > /dev/null; then\n  echo "ERROR: Logs sync process failed to start"\n  exit 1\nfi\n{{- end }}\necho "Starting training process"\naccelerate launch \\\n  --config_file /configs/accelerate_config.yaml \\\n  --no-python \\\n  finetuning --num-preprocess-workers 4 {{ .Values.finetuning_config.method }} /configs/finetuning_config.yaml\necho "Training done, stop the upload process"\nkill $uploadPID\nwait $uploadPID || true\n{{- if .Values.runTensorboard }}\nkill $logsPID\nwait $logsPID || true\n{{- end }}\n{{- if (not (eq .Values.finetuning_config.peft_conf.peft_type "NO_PEFT")) }}\necho "Running adapter post-processing:"\ncreate_vllm_compatible_adapter --training-config /configs/finetuning_config.yaml ./checkpoints/checkpoint-final-adapter\n# Sync the final checkpoint with overwrite to carry over vLLM-compatibility changes\nmc mirror \\\n  --overwrite \\\n  /workdir/checkpoints/checkpoint-final-adapter \\\n  {{ $checkpointsRemotePath }}checkpoint-final-adapter/\n{{- if .Values.mergeAdapter }}\nmerge_base=/local_resources/basemodel\nif [ -d ./checkpoints/checkpoint-new-basemodel ]; then\n  merge_base=./checkpoints/checkpoint-new-basemodel\nfi\nmerge_adapter $merge_base ./checkpoints/checkpoint-final-adapter ./checkpoints/checkpoint-final\n{{- end }}\n{{- end }}\n# Once more to ensure everything gets uploaded\necho 'Training done, syncing once more...'\nmc mirror \\\n  /workdir/checkpoints \\\n  {{ $checkpointsRemotePath }}\n{{- if .Values.runTensorboard }}\nmc mirror \\\n  /workdir/logs \\\n  {{ $logsRemotePath }}\n{{- end }}\necho 'All done, exiting'\n{{- end }}\n	4d4c0334-f713-4550-a99c-22f3ecdcf5b8	2026-03-17 12:30:30.860147+00	2026-03-17 12:30:30.860147+00	system	system
4c1ec031-235c-41e6-a567-ce542ab7542d	templates/configmap.yaml	apiVersion: v1\nkind: ConfigMap\nmetadata:\n  name: "{{ .Release.Name }}-configs"\ndata:\n  accelerate_config.yaml: |\n    {{- if (eq .Values.distributedType "auto-deepspeed-stage1" ) }}\n    compute_environment: LOCAL_MACHINE\n    distributed_type: DEEPSPEED\n    deepspeed_config:\n      zero_stage: 1\n      bf16:\n        enabled: true\n    fsdp_config: {}\n    machine_rank: 0\n    main_process_ip: null\n    main_process_port: null\n    mixed_precision: bf16\n    num_machines: 1\n    num_processes: {{ .Values.finetuningGpus }}\n    use_cpu: false\n    {{- else if (eq .Values.distributedType "auto-deepspeed-stage3") }}\n    compute_environment: LOCAL_MACHINE\n    distributed_type: DEEPSPEED\n    deepspeed_config:\n      zero_stage: 3\n      bf16:\n        enabled: true\n      offload_optimizer_device: none\n      offload_param_device: none\n      zero3_init_flag: true\n      zero3_save_16bit_model: true\n    fsdp_config: {}\n    machine_rank: 0\n    main_process_ip: null\n    main_process_port: null\n    mixed_precision: bf16\n    num_machines: 1\n    num_processes: {{ .Values.finetuningGpus }}\n    use_cpu: false\n    {{- else if (eq .Values.distributedType "auto-single-process") }}\n    compute_environment: LOCAL_MACHINE\n    distributed_type: NO\n    fsdp_config: {}\n    machine_rank: 0\n    main_process_ip: null\n    main_process_port: null\n    mixed_precision: bf16\n    num_machines: 1\n    num_processes: 1\n    use_cpu: false\n    {{- else if (eq .Values.distributedType "auto-ddp") }}\n    compute_environment: LOCAL_MACHINE\n    debug: false\n    distributed_type: MULTI_GPU\n    downcast_bf16: 'no'\n    enable_cpu_affinity: false\n    machine_rank: 0\n    main_training_function: main\n    mixed_precision: bf16\n    num_machines: 1\n    num_processes: {{ .Values.finetuningGpus }}\n    rdzv_backend: static\n    same_network: true\n    tpu_env: []\n    tpu_use_cluster: false\n    tpu_use_sudo: false\n    use_cpu: false\n    {{- else if (eq .Values.distributedType "custom-accelerate-config") }}\n    {{- toYaml .Values.customAccelerateConfig | nindent 4 }}\n    {{- end }}\n  finetuning_config.yaml: |\n    {{- with .Values.finetuning_config }}\n    method: {{ .method }}\n    data_conf:\n      training_data:\n        type: {{ .data_conf.training_data.type }}\n        datasets:\n          {{- $get_train_sampling_weight := (eq .data_conf.training_data.type "PRECOMPUTE_WEIGHTED_MIX") }}\n          {{- range .data_conf.training_data.datasets }}\n          - path: /local_resources/{{ .path | replace "/" "_" }}\n          {{- if $get_train_sampling_weight }}\n            sampling_weight: {{ default 1.0 .sampling_weight }}\n          {{- end }}\n          {{- end }}\n      validation_data:\n        type: {{ .data_conf.validation_data.type }}\n        {{- if (eq .data_conf.validation_data.type "AUTO_SPLIT") }}\n        ratio: {{ .data_conf.validation_data.ratio }}\n        {{- else if (eq .validation_data_type "CONCATENATION") }}\n        datasets:\n          {{- range .data_conf.validation_data.datasets }}\n          - path: /local_resources/{{ .path | replace "/" "_" }}\n          {{- end }}\n        {{- end }}\n      chat_template_name: {{ .data_conf.chat_template_name }}\n      missing_pad_token_strategy: {{ .data_conf.missing_pad_token_strategy }}\n    training_args:\n      {{- toYaml .training_args | nindent 6 }}\n    overrides:\n      {{- toYaml .overrides | nindent 6 }}\n    batchsize_conf:\n      total_train_batch_size: {{ default $.Values.finetuningGpus .batchsize_conf.total_train_batch_size }}\n      max_per_device_train_batch_size: {{ .batchsize_conf.max_per_device_train_batch_size }}\n      per_device_eval_batch_size: {{ default "null" .batchsize_conf.per_device_eval_batch_size }}\n    peft_conf:\n      {{- toYaml .peft_conf | nindent 6 }}\n    quant_conf:\n      {{- toYaml .quant_conf | nindent 6 }}\n    run_conf:\n      model: /local_resources/basemodel\n      final_checkpoint_name: {{ ternary "checkpoint-final" "checkpoint-final-adapter" (eq .peft_conf.peft_type "NO_PEFT") }}\n      {{- toYaml .run_conf | nindent 6 }}\n    {{- if (eq .method "sft") }}\n    sft_args:\n      {{- toYaml .sft_args | nindent 6 }}\n    {{- end }}\n    {{- if .tracking }}\n    tracking:\n      {{- toYaml .tracking | nindent 6 }}\n    {{- end }}\n    {{- end }}\n	4d4c0334-f713-4550-a99c-22f3ecdcf5b8	2026-03-17 12:30:30.860149+00	2026-03-17 12:30:30.86015+00	system	system
e90c93e5-1e12-4c9b-adcf-e474c8e99088	values.schema.json	{\n  "$schema": "http://json-schema.org/draft-07/schema#",\n  "type": "object",\n  "properties": {\n    "fullnameOverride": {\n      "type": "string",\n      "description": "String to fully override the deployment name"\n    },\n    "metadata": {\n      "type": "object",\n      "description": "Metadata for the deployment",\n      "properties": {\n        "labels": {\n          "type": "object",\n          "description": "Labels to apply to the deployment",\n          "additionalProperties": {\n            "type": "string"\n          }\n        },\n        "project_id": {\n          "type": "string",\n          "description": "Project ID for the deployment"\n        },\n        "user_id": {\n          "type": "string",\n          "description": "User ID for the deployment"\n        },\n        "workload_id": {\n          "type": ["string", "null"],\n          "description": "Workload ID for the deployment (defaults to release name if not set)"\n        }\n      },\n      "required": ["labels"]\n    },\n    "image": {\n      "type": "string",\n      "description": "Docker image to use for the deployment"\n    },\n    "imagePullPolicy": {\n      "type": "string",\n      "description": "Image pull policy",\n      "enum": ["Always", "IfNotPresent", "Never"]\n    },\n    "model": {\n      "type": "string",\n      "description": "Model to use for inference"\n    },\n    "served_model_name": {\n      "type": ["string", "null"],\n      "description": "Optional explicit model name for API requests (defaults to model if not set)"\n    },\n    "gpus": {\n      "type": "integer",\n      "description": "Number of GPUs to allocate",\n      "minimum": 1\n    },\n    "memory_per_gpu": {\n      "type": "integer",\n      "description": "Memory per GPU in Gi",\n      "minimum": 1\n    },\n    "cpu_per_gpu": {\n      "type": "integer",\n      "description": "CPU cores per GPU",\n      "minimum": 1\n    },\n    "vllm_engine_args": {\n      "type": "object",\n      "description": "Arguments for the vllm engine",\n      "additionalProperties": {\n        "type": ["string", "null"]\n      }\n    },\n    "env_vars": {\n      "type": "object",\n      "description": "Environment variables for the deployment",\n      "properties": {\n        "BUCKET_STORAGE_HOST": {\n          "type": "string",\n          "description": "Bucket storage host URL",\n          "format": "uri"\n        },\n        "BUCKET_STORAGE_ACCESS_KEY": {\n          "type": "object",\n          "description": "Access key for bucket storage",\n          "properties": {\n            "name": {\n              "type": "string",\n              "description": "Name of the secret containing the access key"\n            },\n            "key": {\n              "type": "string",\n              "description": "Key in the secret containing the access key"\n            }\n          },\n          "required": ["name", "key"]\n        },\n        "BUCKET_STORAGE_SECRET_KEY": {\n          "type": "object",\n          "description": "Secret key for bucket storage",\n          "properties": {\n            "name": {\n              "type": "string",\n              "description": "Name of the secret containing the secret key"\n            },\n            "key": {\n              "type": "string",\n              "description": "Key in the secret containing the secret key"\n            }\n          },\n          "required": ["name", "key"]\n        },\n        "HF_HOME": {\n          "type": "string",\n          "description": "Home directory for Hugging Face"\n        }\n      },\n      "required": ["BUCKET_STORAGE_HOST", "BUCKET_STORAGE_ACCESS_KEY", "BUCKET_STORAGE_SECRET_KEY", "HF_HOME"]\n    },\n    "storage": {\n      "type": "object",\n      "description": "Storage configuration",\n      "properties": {\n        "ephemeral": {\n          "type": "object",\n          "description": "Ephemeral storage configuration",\n          "properties": {\n            "quantity": {\n              "type": "string",\n              "description": "Quantity of ephemeral storage"\n            },\n            "storageClassName": {\n              "type": "string",\n              "description": "Storage class name for ephemeral storage"\n            },\n            "accessModes": {\n              "type": "array",\n              "description": "Access modes for ephemeral storage",\n              "items": {\n                "type": "string"\n              }\n            }\n          },\n          "required": ["quantity", "storageClassName", "accessModes"]\n        },\n        "dshm": {\n          "type": "object",\n          "description": "Shared memory configuration",\n          "properties": {\n            "sizeLimit": {\n              "type": "string",\n              "description": "Size limit for shared memory"\n            }\n          },\n          "required": ["sizeLimit"]\n        }\n      },\n      "required": ["ephemeral", "dshm"]\n    },\n    "deployment": {\n      "type": "object",\n      "description": "Deployment configuration",\n      "properties": {\n        "ports": {\n          "type": "object",\n          "description": "Ports for the deployment",\n          "properties": {\n            "http": {\n              "type": "integer",\n              "description": "HTTP port for the deployment"\n            }\n          },\n          "required": ["http"]\n        }\n      },\n      "required": ["ports"]\n    },\n    "kaiwo": {\n      "type": "object",\n      "properties": {\n        "enabled": {\n          "type": "boolean",\n          "description": "If true, use Kaiwo CRDs to have Kaiwo operator manage the workload"\n        }\n      }\n    },\n    "startupProbe": {\n      "type": ["object"],\n      "additionalProperties": true,\n      "description": "Startup probe configuration for the container"\n    },\n    "livenessProbe": {\n      "type": ["object"],\n      "additionalProperties": true,\n      "description": "Liveness probe configuration for the container"\n    },\n    "readinessProbe": {\n      "type": ["object"],\n      "additionalProperties": true,\n      "description": "Readiness probe configuration for the container"\n    },\n    "http_route": {\n      "type": "object",\n      "description": "HTTP route configuration",\n      "properties": {\n        "enabled": {\n          "type": "boolean",\n          "description": "Enable HTTP route"\n        }\n      },\n      "required": ["enabled"]\n    },\n    "ingress": {\n      "type": "object",\n      "description": "Ingress configuration",\n      "properties": {\n        "enabled": {\n          "type": "boolean",\n          "description": "Enable ingress"\n        }\n      },\n      "required": ["enabled"]\n    },\n    "replicas": {\n      "type": "integer",\n      "description": "Number of replicas to run",\n      "minimum": 1\n    }\n  },\n  "required": [\n    "metadata",\n    "image",\n    "imagePullPolicy",\n    "model",\n    "gpus",\n    "memory_per_gpu",\n    "cpu_per_gpu",\n    "vllm_engine_args",\n    "env_vars",\n    "storage",\n    "deployment",\n    "kaiwo",\n    "startupProbe",\n    "livenessProbe",\n    "readinessProbe",\n    "http_route",\n    "ingress",\n    "replicas"\n  ],\n  "additionalProperties": false\n}\n	cfbe1c00-8b21-45d5-bce1-6a1926addb7d	2026-03-17 12:30:30.993097+00	2026-03-17 12:30:30.993098+00	system	system
8edf06f3-b209-4c3b-acc6-7f1647d6d207	Chart.yaml	apiVersion: v2\nname: llm-inference-vllm\ndescription: A Helm chart for vLLM inference\nversion: 0.0.1\n	cfbe1c00-8b21-45d5-bce1-6a1926addb7d	2026-03-17 12:30:30.993102+00	2026-03-17 12:30:30.993102+00	system	system
5837d3a8-decc-46a7-ae22-011e5bad04a6	values.yaml	metadata:\n  labels: {}\n  project_id: silogen\n  user_id: user\n  workload_id: # defaults to the release name\n\nimage: "rocm/vllm:rocm6.4.1_vllm_0.9.0.1_20250605"\nimagePullPolicy: Always\nreplicas: 1\n\nmodel: "TinyLlama/TinyLlama-1.1B-Chat-v1.0"\nserved_model_name: # Optional: explicit served model name for API requests\ngpus: 1\nmemory_per_gpu: 64 # Gi\ncpu_per_gpu: 4\n\n# vllm engine args (ref: https://docs.vllm.ai/en/latest/serving/engine_args.html)\n# allows flag arguments to be passed to the cli by leaving empty. for example:\n# example-flag:\nvllm_engine_args:\n  # tensor-parallel-size: "{{ .Values.gpus }}"  # taken care of by the template\n  # model: "{{ .Values.model }}"  # taken care of by the template\n  # served-model-name: "{{ .Values.served_model_name }}"  # taken care of by the template\n  gpu-memory-utilization: "0.95"\n  distributed_executor_backend: "mp"\n  no-enable-chunked-prefill:\n\n# env vars (vllm ref: https://docs.vllm.ai/en/latest/serving/env_vars.html)\nenv_vars:\n  BUCKET_STORAGE_HOST: http://minio.minio-tenant-default.svc.cluster.local:80\n  BUCKET_STORAGE_ACCESS_KEY:\n    name: minio-credentials\n    key: minio-access-key\n  BUCKET_STORAGE_SECRET_KEY:\n    name: minio-credentials\n    key: minio-secret-key\n  HF_HOME: /workload/.cache/huggingface\n\n  # vLLM optimized settings: https://blog.vllm.ai/2024/10/23/vllm-serving-amd.html\n  VLLM_DO_NOT_TRACK: "1"\n  VLLM_USE_V1: "0"\n  VLLM_USE_TRITON_FLASH_ATTN: "0" # Use Composable Kernel (CK) Flash Attention instead of Triton Flash Attention\n  HIP_FORCE_DEV_KERNARG: "1"\n  NCCL_MIN_NCHANNELS: "112"\n  TORCH_BLAS_PREFER_HIPBLASLT: "1"\n  PYTORCH_TUNABLEOP_ENABLED: "1"\n  PYTORCH_TUNABLEOP_VERBOSE: "1"\n  PYTORCH_TUNABLEOP_TUNING: "0"\n\nstorage:\n  ephemeral:\n    quantity: 256Gi\n    storageClassName: mlstorage\n    accessModes:\n      - ReadWriteOnce\n  dshm:\n    sizeLimit: 32Gi\n\ndeployment:\n  ports:\n    http: 8080\n\n# startupProbe - checks if the container has successfully started. It disables liveness and readiness probes until it succeeds, useful for slow-starting applications.\n# livenessProbe - checks if the container is still alive. If it fails, Kubernetes restarts the container to recover from failure.\n# readinessProbe - checks if the container is ready to serve traffic. If it fails, the container is removed from the service's endpoints but remains running.\n# ref: https://kubernetes.io/docs/tasks/configure-pod-container/configure-liveness-readiness-startup-probes/\nstartupProbe:\n  httpGet:\n    path: /v1/models\n    port: http\n  periodSeconds: 10\n  failureThreshold: 360 # 360 x 10s => allow for 60 minutes startup time\nlivenessProbe:\n  httpGet:\n    path: /health\n    port: http\nreadinessProbe:\n  httpGet:\n    path: /v1/models\n    port: http\n\n# kaiwo settings (if enabled, use kaiwo CRDs to have kaiwo operator manage the workload)\nkaiwo:\n  enabled: false\n\nhttp_route:\n  enabled: false\n\ningress:\n  enabled: false\n	cfbe1c00-8b21-45d5-bce1-6a1926addb7d	2026-03-17 12:30:30.993104+00	2026-03-17 12:30:30.993105+00	system	system
5a74d49c-5d58-4619-8626-4021c3fe0deb	templates/_helpers.tpl	# Base URL helper\n{{- define "httpRoute.baseUrl" -}}\n{{- $projectId := default "project_id" .Values.metadata.project_id -}}\n{{- $userId := default "user_id" .Values.metadata.user_id -}}\n{{- $workloadId := default (include "release.fullname" .) .Values.metadata.workload_id -}}\n{{- printf "/%s/%s/%s" $projectId $userId $workloadId }}\n{{- end -}}\n\n# Release name helper\n{{- define "release.name" -}}\n{{- default .Chart.Name .Values.nameOverride | trunc 63 | trimSuffix "-" -}}\n{{- end -}}\n\n# Release fullname helper\n{{- define "release.fullname" -}}\n{{- $currentTime := now | date "20060102-1504" -}}\n{{- if .Values.fullnameOverride -}}\n{{- .Values.fullnameOverride | trunc 63 | trimSuffix "-" -}}\n{{- else -}}\n{{- if ne .Release.Name "release-name" -}}\n{{- include "release.name" . }}-{{ .Release.Name | trunc 63 | trimSuffix "-" -}}\n{{- else -}}\n{{- include "release.name" . }}-{{ $currentTime | lower | trunc 63 | trimSuffix "-" -}}\n{{- end -}}\n{{- end -}}\n{{- end -}}\n\n# Container resources helper\n{{- define "container.resources" -}}\nrequests:\n  memory: "{{ max (mul .Values.gpus .Values.memory_per_gpu) 4 }}Gi"\n  cpu: "{{ max (mul .Values.gpus .Values.cpu_per_gpu) 1 }}"\n  {{- if .Values.gpus }}\n  amd.com/gpu: "{{ .Values.gpus }}"\n  {{- end }}\nlimits:\n  memory: "{{ max (mul .Values.gpus .Values.memory_per_gpu) 4 }}Gi"\n  cpu: "{{ max (mul .Values.gpus .Values.cpu_per_gpu) 1 }}"\n  {{- if .Values.gpus }}\n  amd.com/gpu: "{{ .Values.gpus }}"\n  {{- end }}\n{{- end -}}\n\n# Container environment variables helper\n{{- define "container.env" -}}\n{{- range $key, $value := .Values.env_vars }}\n{{- if (typeIs "string" $value) }}\n- name: {{ $key }}\n  value: {{ $value | quote }}\n{{- else if and $value (kindIs "map" $value) (hasKey $value "name") (hasKey $value "key") }}\n- name: {{ $key }}\n  valueFrom:\n    secretKeyRef:\n      name: {{ $value.name }}\n      key: {{ $value.key }}\n{{- else }}\n- name: {{ $key }}\n  value: {{ $value | toString | quote }}\n{{- end }}\n{{- end }}\n{{- end -}}\n\n# Container volume mounts helper\n{{- define "container.volumeMounts" -}}\n- mountPath: /workload\n  name: ephemeral-storage\n- mountPath: /workload/mount\n  name: workload-mount\n- mountPath: /dev/shm\n  name: dshm\n{{- end -}}\n\n# Container volumes helper\n{{- define "container.volumes" -}}\n{{- if .Values.storage.ephemeral.storageClassName -}}\n- ephemeral:\n    volumeClaimTemplate:\n      spec:\n        {{- if .Values.storage.ephemeral.accessModes }}\n        accessModes: {{ .Values.storage.ephemeral.accessModes }}\n        {{- else }}\n        accessModes:\n          - ReadWriteOnce\n        {{- end }}\n        resources:\n          requests:\n            storage: {{ .Values.storage.ephemeral.quantity }}\n        storageClassName: {{ .Values.storage.ephemeral.storageClassName }}\n  name: ephemeral-storage\n{{- else }}\n- emptyDir: {}\n  name: ephemeral-storage\n  sizeLimit: {{ .Values.storage.ephemeral.quantity }}\n{{- end }}\n- emptyDir:\n    medium: Memory\n    sizeLimit: {{ .Values.storage.dshm.sizeLimit }}\n  name: dshm\n- configMap:\n    name: {{ include "release.fullname" . }}\n  name: workload-mount\n{{- end -}}\n	cfbe1c00-8b21-45d5-bce1-6a1926addb7d	2026-03-17 12:30:30.993107+00	2026-03-17 12:30:30.993107+00	system	system
791978a6-6700-46e1-9b1f-a4b5a46d7e2b	templates/ingress.yaml	{{- if .Values.ingress.enabled -}}\napiVersion: networking.k8s.io/v1\nkind: Ingress\nmetadata:\n  name: {{ include "release.fullname" . }}\n  annotations:\n    nginx.ingress.kubernetes.io/enable-websocket: "true"\n    nginx.ingress.kubernetes.io/proxy-connect-timeout: "3600"\n    nginx.ingress.kubernetes.io/proxy-http-version: "1.1"\n    nginx.ingress.kubernetes.io/proxy-read-timeout: "3600"\n    nginx.ingress.kubernetes.io/proxy-send-timeout: "3600"\n    nginx.ingress.kubernetes.io/proxy-set-header-Origin: ""\n    nginx.ingress.kubernetes.io/rewrite-target: /$2\n    nginx.ingress.kubernetes.io/use-regex: "true"\nspec:\n  rules:\n  - http:\n      paths:\n      - backend:\n          service:\n            name: {{ include "release.fullname" . }}\n            port:\n              number: 80\n        path: {{ include "httpRoute.baseUrl" . }}(/|$)(.*)\n        pathType: ImplementationSpecific\n{{- end -}}\n	cfbe1c00-8b21-45d5-bce1-6a1926addb7d	2026-03-17 12:30:30.99311+00	2026-03-17 12:30:30.99311+00	system	system
5a8031b7-1a14-4513-bb2d-8606fe680c8a	templates/deployment.yaml	{{- define "deployment" -}}\napiVersion: apps/v1\nkind: Deployment\nmetadata:\n  name: {{ include "release.fullname" . }}\n  labels:\n    app: {{ include "release.fullname" . }}\n    {{- range $key, $value := .Values.metadata.labels }}\n    {{ $key }}: {{ $value | quote }}\n    {{- end }}\nspec:\n  replicas: {{ .Values.replicas | default 1 }}\n  selector:\n    matchLabels:\n      app: {{ include "release.fullname" . }}\n  template:\n    metadata:\n      labels:\n        app: {{ include "release.fullname" . }}\n    spec:\n      containers:\n        - name: {{ .Chart.Name }}\n          args:\n          - |\n            {{- include "entrypoint" . | nindent 12 }}\n          command: ["sh", "-c"]\n          {{- if .Values.env_vars }}\n          env:\n            {{- include "container.env" . | nindent 12 }}\n          {{- end }}\n          image: {{ .Values.image | quote}}\n          imagePullPolicy: {{ default "Always" .Values.imagePullPolicy | quote }}\n          {{- if .Values.livenessProbe }}\n          livenessProbe:\n            {{- .Values.livenessProbe | toYaml | nindent 12 -}}\n          {{- end }}\n          ports:\n            {{- range $key, $value := .Values.deployment.ports }}\n            - name: {{ $key }}\n              containerPort: {{ $value }}\n            {{- end }}\n          {{- if .Values.readinessProbe }}\n          readinessProbe:\n            {{- .Values.readinessProbe | toYaml | nindent 12 -}}\n          {{- end }}\n          resources:\n            {{- include "container.resources" . | nindent 12 }}\n          {{- if .Values.startupProbe }}\n          startupProbe:\n            {{- .Values.startupProbe | toYaml | nindent 12 -}}\n          {{- end }}\n          volumeMounts:\n            {{- include "container.volumeMounts" . | nindent 12 }}\n      volumes:\n        {{- include "container.volumes" . | nindent 8 }}\n{{- end -}}\n\n{{- define "deployment_stripped" -}}\n{{- $deployment := include "deployment" . | fromYaml }}\n{{- $ := unset $deployment "metadata" }}\n{{- $ := unset $deployment.spec.template "metadata" }}\n{{- $deployment | toYaml }}\n{{- end -}}\n\n{{- define "deployment_wrapped_with_kaiwoservice" -}}\napiVersion: kaiwo.silogen.ai/v1alpha1\nkind: KaiwoService\nmetadata:\n  name: {{ include "release.fullname" . }}\n  labels:\n    app: {{ include "release.fullname" . }}\n    {{- range $key, $value := .Values.metadata.labels }}\n    {{ $key }}: {{ $value | quote }}\n    {{- end }}\nspec:\n  deployment:\n    {{- include "deployment" . | nindent 4 }}\n{{- end -}}\n\n{{- if .Values.kaiwo.enabled -}}\n{{- include "deployment_wrapped_with_kaiwoservice" . }}\n{{- else -}}\n{{- include "deployment" . }}\n{{- end -}}\n	cfbe1c00-8b21-45d5-bce1-6a1926addb7d	2026-03-17 12:30:30.993112+00	2026-03-17 12:30:30.993113+00	system	system
074368dd-a87b-465f-bdbf-5c6d63451648	templates/service.yaml	apiVersion: v1\nkind: Service\nmetadata:\n  name: {{ include "release.fullname" . }}\n  labels:\n    app: {{ include "release.fullname" . }}\nspec:\n  type: ClusterIP\n  ports:\n    {{ range $name, $port := .Values.deployment.ports }}\n    {{- if ne $name "http" }}\n    - name: {{ $name }}\n      port: {{ $port }}\n      targetPort: {{ $port }}\n    {{- else -}}\n    - name: {{ $name }}\n      port: 80\n      targetPort: {{ $port }}\n    {{- end }}\n    {{- end }}\n  selector:\n    app: {{ include "release.fullname" . }}\n	cfbe1c00-8b21-45d5-bce1-6a1926addb7d	2026-03-17 12:30:30.993115+00	2026-03-17 12:30:30.993115+00	system	system
b98a8c62-eb6e-497c-8891-9543533d56e3	templates/_entrypoint.tpl	{{- define "minio.setup" -}}\n{{- $model := trimPrefix "s3://" .Values.model | trimSuffix "/" -}}\n{{- $minioModel := printf "minio-host/%s" $model -}}\n{{- $localModel := printf "/workload/%s" $model -}}\necho '--------------------------------------------'\necho 'Installing minio client'\necho '--------------------------------------------'\ncurl https://dl.min.io/client/mc/release/linux-amd64/mc \\\n      --create-dirs \\\n      -o /minio-binaries/mc\nchmod +x /minio-binaries/mc\nexport PATH="${PATH}:/minio-binaries/"\nif ! command -v mc >/dev/null 2>&1; then\n  echo "ERROR: MinIO client (mc) is not available after installation."\n  exit 1\nfi\nmc alias set minio-host ${BUCKET_STORAGE_HOST} ${BUCKET_STORAGE_ACCESS_KEY} ${BUCKET_STORAGE_SECRET_KEY} || { echo "ERROR: Failed to set MinIO alias."; exit 1; }\necho '--------------------------------------------'\necho 'Checking if model exists in MinIO storage'\necho '--------------------------------------------'\necho "Looking for files at: {{$minioModel -}}/"\nFILE_COUNT=$(mc find {{$minioModel -}}/ 2>/dev/null | wc -l)\nif [ "$FILE_COUNT" -eq 0 ]; then\n  echo "ERROR: No files found at '{{$minioModel -}}/' or path does not exist."\n  echo "DEBUG: mc find command output:"\n  mc find {{$minioModel -}}/ 2>&1\n  exit 1\nfi\necho "✓ Found $FILE_COUNT files at {{$minioModel -}}/"\necho '--------------------------------------------'\necho 'Downloading the model to the local container'\necho '--------------------------------------------'\nif ! mc mirror {{$minioModel -}}/ {{$localModel -}}/ 2> /tmp/mc_mirror_error.log; then\n  echo "ERROR: Failed to download model from '{{$minioModel -}}/'."\n  echo "DEBUG: mc mirror command stderr output:"\n  cat /tmp/mc_mirror_error.log\n  exit 1\nfi\n{{- end -}}\n\n{{- define "vllm.start" -}}\n{{- $modelPath := .Values.model -}}\n{{- if (hasPrefix "s3://" .Values.model) -}}\n  {{- $modelPath = printf "/workload/%s" (trimPrefix "s3://" .Values.model | trimSuffix "/") -}}\n{{- end -}}\necho '--------------------------------------------'\necho 'Starting vLLM'\necho '--------------------------------------------'\npip install huggingface_hub[hf_xet]\npython3 -m vllm.entrypoints.openai.api_server \\\n{{- range $key, $value := .Values.vllm_engine_args }}\n{{- if eq $value nil }}\n--{{ $key }} \\\n{{- else }}\n--{{ $key }}={{ tpl $value $ | quote }} \\\n{{- end }}\n{{- end }}\n--model={{ $modelPath }} \\\n{{- if .Values.served_model_name }}\n--served-model-name={{ .Values.served_model_name | quote }} \\\n{{- end }}\n--tensor-parallel-size={{ .Values.gpus }} \\\n--host="0.0.0.0" \\\n--port=8080\n{{- end -}}\n\n{{ define "entrypoint" -}}\n{{- if (hasPrefix "s3://" .Values.model) -}}\n{{- include "minio.setup" . -}}\n{{- end }}\n{{ include "vllm.start" . -}}\n{{- end -}}\n	cfbe1c00-8b21-45d5-bce1-6a1926addb7d	2026-03-17 12:30:30.993117+00	2026-03-17 12:30:30.993118+00	system	system
acdf67f3-a0e1-46db-a2d8-37fd886ef03a	templates/configmap.yaml	apiVersion: v1\nkind: ConfigMap\nmetadata:\n  name: {{ include "release.fullname" . }}\ndata:\n{{- $files := .Files }}\n{{- range $path, $_ := .Files.Glob "mount/*" }}\n  {{ $key := $path | trimPrefix "mount/" }}\n  {{- $key }}: |\n{{ $files.Get $path | indent 4 }}\n{{- end }}\n	cfbe1c00-8b21-45d5-bce1-6a1926addb7d	2026-03-17 12:30:30.993123+00	2026-03-17 12:30:30.993123+00	system	system
